  1→// ── Model selector ──────────────────────────────────────────
  2→
  3→import { sendRpc } from "./helpers.js";
  4→import { t } from "./i18n.js";
  5→import { showModelNotice } from "./page-chat.js";
  6→import * as S from "./state.js";
  7→import { modelStore } from "./stores/model-store.js";
  8→
  9→function setSessionModel(sessionKey, modelId) {
 10→	sendRpc("sessions.patch", { key: sessionKey, model: modelId });
 11→}
 12→
 13→export { setSessionModel };
 14→
 15→function updateModelComboLabel(model) {
 16→	if (S.modelComboLabel) S.modelComboLabel.textContent = model.displayName || model.id;
 17→}
 18→
 19→export function fetchModels() {
 20→	return modelStore.fetch().then(() => {
 21→		// Dual-write to state.js for backward compat
 22→		S.setModels(modelStore.models.value);
 23→		S.setSelectedModelId(modelStore.selectedModelId.value);
 24→		var model = modelStore.selectedModel.value;
 25→		if (model) updateModelComboLabel(model);
 26→
 27→		// If the dropdown is currently open, re-render to reflect updated flags
 28→		// (for example when a model becomes unsupported via a WS event).
 29→		if (S.modelDropdown && !S.modelDropdown.classList.contains("hidden")) {
 30→			var query = S.modelSearchInput ? S.modelSearchInput.value.trim() : "";
 31→			renderModelList(query);
 32→		}
 33→	});
 34→}
 35→
 36→export function selectModel(m) {
 37→	modelStore.select(m.id);
 38→	// Dual-write to state.js for backward compat
 39→	S.setSelectedModelId(m.id);
 40→	updateModelComboLabel(m);
 41→	localStorage.setItem("moltis-model", m.id);
 42→	setSessionModel(S.activeSessionKey, m.id);
 43→	closeModelDropdown();
 44→	// Show notice if model doesn't support tools
 45→	showModelNotice(m);
 46→}
 47→
 48→export function openModelDropdown() {
 49→	if (!S.modelDropdown) return;
 50→	S.modelDropdown.classList.remove("hidden");
 51→	S.modelSearchInput.value = "";
 52→	S.setModelIdx(-1);
 53→	renderModelList("");
 54→	requestAnimationFrame(() => {
 55→		if (S.modelSearchInput) S.modelSearchInput.focus();
 56→	});
 57→}
 58→
 59→export function closeModelDropdown() {
 60→	if (!S.modelDropdown) return;
 61→	S.modelDropdown.classList.add("hidden");
 62→	if (S.modelSearchInput) S.modelSearchInput.value = "";
 63→	S.setModelIdx(-1);
 64→}
 65→
 66→function buildModelItem(m, currentId) {
 67→	var el = document.createElement("div");
 68→	el.className = "model-dropdown-item";
 69→	if (m.id === currentId) el.classList.add("selected");
 70→	if (m.unsupported) el.classList.add("model-dropdown-item-unsupported");
 71→
 72→	var label = document.createElement("span");
 73→	label.className = "model-item-label";
 74→	label.textContent = m.displayName || m.id;
 75→	el.appendChild(label);
 76→
 77→	var meta = document.createElement("span");
 78→	meta.className = "model-item-meta";
 79→
 80→	if (m.provider) {
 81→		var prov = document.createElement("span");
 82→		prov.className = "model-item-provider";
 83→		prov.textContent = m.provider;
 84→		meta.appendChild(prov);
 85→	}
 86→
 87→	if (m.unsupported) {
 88→		var badge = document.createElement("span");
 89→		badge.className = "model-item-unsupported";
 90→		badge.textContent = t("common:labels.unsupported");
 91→		if (m.unsupportedReason) badge.title = m.unsupportedReason;
 92→		meta.appendChild(badge);
 93→	}
 94→
 95→	if (meta.childNodes.length > 0) el.appendChild(meta);
 96→	el.addEventListener("click", () => selectModel(m));
 97→	return el;
 98→}
 99→
100→export function renderModelList(query) {
101→	if (!S.modelDropdownList) return;
102→	S.modelDropdownList.textContent = "";
103→	var q = query.toLowerCase();
104→	var allModels = modelStore.models.value;
105→	var filtered = allModels.filter((m) => {
106→		var label = (m.displayName || m.id).toLowerCase();
107→		var provider = (m.provider || "").toLowerCase();
108→		return !q || label.indexOf(q) !== -1 || provider.indexOf(q) !== -1 || m.id.toLowerCase().indexOf(q) !== -1;
109→	});
110→	if (filtered.length === 0) {
111→		var empty = document.createElement("div");
112→		empty.className = "model-dropdown-empty";
113→		empty.textContent = t("common:labels.noMatchingModels");
114→		S.modelDropdownList.appendChild(empty);
115→		return;
116→	}
117→	var currentId = modelStore.selectedModelId.value;
118→	var lastPreferredIdx = filtered.findLastIndex((m) => m.preferred);
119→	filtered.forEach((m, idx) => {
120→		S.modelDropdownList.appendChild(buildModelItem(m, currentId));
121→
122→		if (idx === lastPreferredIdx && lastPreferredIdx < filtered.length - 1) {
123→			var divider = document.createElement("div");
124→			divider.className = "model-dropdown-divider";
125→			S.modelDropdownList.appendChild(divider);
126→		}
127→	});
128→}
129→
130→function updateModelActive() {
131→	if (!S.modelDropdownList) return;
132→	var items = S.modelDropdownList.querySelectorAll(".model-dropdown-item");
133→	items.forEach((el, i) => {
134→		el.classList.toggle("kb-active", i === S.modelIdx);
135→	});
136→	if (S.modelIdx >= 0 && items[S.modelIdx]) {
137→		items[S.modelIdx].scrollIntoView({ block: "nearest" });
138→	}
139→}
140→
141→export function bindModelComboEvents() {
142→	if (!(S.modelComboBtn && S.modelSearchInput && S.modelDropdownList && S.modelCombo)) return;
143→
144→	S.modelComboBtn.addEventListener("click", () => {
145→		if (S.modelDropdown.classList.contains("hidden")) {
146→			openModelDropdown();
147→		} else {
148→			closeModelDropdown();
149→		}
150→	});
151→
152→	S.modelSearchInput.addEventListener("input", () => {
153→		S.setModelIdx(-1);
154→		renderModelList(S.modelSearchInput.value.trim());
155→	});
156→
157→	S.modelSearchInput.addEventListener("keydown", (e) => {
158→		var items = S.modelDropdownList.querySelectorAll(".model-dropdown-item");
159→		if (e.key === "ArrowDown") {
160→			e.preventDefault();
161→			S.setModelIdx(Math.min(S.modelIdx + 1, items.length - 1));
162→			updateModelActive();
163→		} else if (e.key === "ArrowUp") {
164→			e.preventDefault();
165→			S.setModelIdx(Math.max(S.modelIdx - 1, 0));
166→			updateModelActive();
167→		} else if (e.key === "Enter") {
168→			e.preventDefault();
169→			if (S.modelIdx >= 0 && items[S.modelIdx]) {
170→				items[S.modelIdx].click();
171→			} else if (items.length === 1) {
172→				items[0].click();
173→			}
174→		} else if (e.key === "Escape") {
175→			closeModelDropdown();
176→			S.modelComboBtn.focus();
177→		}
178→	});
179→}
180→
181→document.addEventListener("click", (e) => {
182→	if (S.modelCombo && !S.modelCombo.contains(e.target)) {
183→		closeModelDropdown();
184→	}
185→});
186→
187→window.addEventListener("moltis:locale-changed", () => {
188→	if (S.modelDropdown && !S.modelDropdown.classList.contains("hidden")) {
189→		var query = S.modelSearchInput ? S.modelSearchInput.value.trim() : "";
190→		renderModelList(query);
191→	}
192→});
193→

 1→// ── Model store (signal-based) ──────────────────────────────
 2→//
 3→// Single source of truth for model data. Both Preact components
 4→// (auto-subscribe) and imperative code (read .value) can use this.
 5→
 6→import { computed, signal } from "@preact/signals";
 7→import { sendRpc } from "../helpers.js";
 8→
 9→// ── Signals ──────────────────────────────────────────────────
10→export var models = signal([]);
11→export var selectedModelId = signal(localStorage.getItem("moltis-model") || "");
12→
13→export var selectedModel = computed(() => {
14→	var id = selectedModelId.value;
15→	return models.value.find((m) => m.id === id) || null;
16→});
17→
18→// ── Methods ──────────────────────────────────────────────────
19→
20→/** Replace the full model list (e.g. after fetch or bootstrap). */
21→export function setAll(arr) {
22→	models.value = arr || [];
23→}
24→
25→/** Fetch models from the server via RPC. */
26→export function fetch() {
27→	return sendRpc("models.list", {}).then((res) => {
28→		if (!res?.ok) return;
29→		setAll(res.payload || []);
30→		if (models.value.length === 0) return;
31→		var saved = localStorage.getItem("moltis-model") || "";
32→		var found = models.value.find((m) => m.id === saved);
33→		var model = found || models.value[0];
34→		select(model.id);
35→		if (!found) localStorage.setItem("moltis-model", model.id);
36→	});
37→}
38→
39→/** Select a model by id. Persists to localStorage. */
40→export function select(id) {
41→	selectedModelId.value = id;
42→}
43→
44→/** Look up a model by id. */
45→export function getById(id) {
46→	return models.value.find((m) => m.id === id) || null;
47→}
48→
49→export var modelStore = { models, selectedModelId, selectedModel, setAll, fetch, select, getById };
50→

