  1→//! ElevenLabs Scribe STT provider implementation.
  2→//!
  3→//! ElevenLabs Scribe provides high-quality speech-to-text with support for
  4→//! 90+ languages, word-level timestamps, and speaker diarization.
  5→
  6→use {
  7→    anyhow::{Context, Result, anyhow},
  8→    async_trait::async_trait,
  9→    reqwest::{
 10→        Client,
 11→        multipart::{Form, Part},
 12→    },
 13→    secrecy::{ExposeSecret, Secret},
 14→    serde::Deserialize,
 15→};
 16→
 17→use {
 18→    super::{SttProvider, TranscribeRequest, Transcript, Word},
 19→    crate::tts::AudioFormat,
 20→};
 21→
 22→/// ElevenLabs API base URL.
 23→const API_BASE: &str = "https://api.elevenlabs.io/v1";
 24→
 25→/// Default model (Scribe v2 for best quality and 150ms latency).
 26→const DEFAULT_MODEL: &str = "scribe_v2";
 27→
 28→/// ElevenLabs Scribe STT provider.
 29→#[derive(Clone)]
 30→pub struct ElevenLabsStt {
 31→    client: Client,
 32→    api_key: Option<Secret<String>>,
 33→    model: String,
 34→    language: Option<String>,
 35→    base_url: String,
 36→}
 37→
 38→impl std::fmt::Debug for ElevenLabsStt {
 39→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 40→        f.debug_struct("ElevenLabsStt")
 41→            .field("api_key", &"[REDACTED]")
 42→            .field("model", &self.model)
 43→            .field("language", &self.language)
 44→            .finish()
 45→    }
 46→}
 47→
 48→impl Default for ElevenLabsStt {
 49→    fn default() -> Self {
 50→        Self::new(None)
 51→    }
 52→}
 53→
 54→impl ElevenLabsStt {
 55→    /// Create a new ElevenLabs Scribe STT provider.
 56→    #[must_use]
 57→    pub fn new(api_key: Option<Secret<String>>) -> Self {
 58→        Self {
 59→            client: Client::new(),
 60→            api_key,
 61→            model: DEFAULT_MODEL.into(),
 62→            language: None,
 63→            base_url: API_BASE.into(),
 64→        }
 65→    }
 66→
 67→    /// Create with custom options.
 68→    #[must_use]
 69→    pub fn with_options(
 70→        api_key: Option<Secret<String>>,
 71→        model: Option<String>,
 72→        language: Option<String>,
 73→    ) -> Self {
 74→        Self {
 75→            client: Client::new(),
 76→            api_key,
 77→            model: model.unwrap_or_else(|| DEFAULT_MODEL.into()),
 78→            language,
 79→            base_url: API_BASE.into(),
 80→        }
 81→    }
 82→
 83→    /// Create with custom base URL (for testing).
 84→    #[allow(clippy::unwrap_used, clippy::expect_used)]
 85→    #[cfg(test)]
 86→    #[must_use]
 87→    pub fn with_base_url(mut self, base_url: impl Into<String>) -> Self {
 88→        self.base_url = base_url.into();
 89→        self
 90→    }
 91→
 92→    /// Get the API key, returning an error if not configured.
 93→    fn get_api_key(&self) -> Result<&Secret<String>> {
 94→        self.api_key
 95→            .as_ref()
 96→            .ok_or_else(|| anyhow!("ElevenLabs API key not configured"))
 97→    }
 98→
 99→    /// Get file extension for audio format.
100→    fn file_extension(format: AudioFormat) -> &'static str {
101→        match format {
102→            AudioFormat::Mp3 => "mp3",
103→            AudioFormat::Opus => "opus",
104→            AudioFormat::Aac => "aac",
105→            AudioFormat::Pcm => "wav",
106→            AudioFormat::Webm => "webm",
107→        }
108→    }
109→}
110→
111→#[async_trait]
112→impl SttProvider for ElevenLabsStt {
113→    fn id(&self) -> &'static str {
114→        "elevenlabs"
115→    }
116→
117→    fn name(&self) -> &'static str {
118→        "ElevenLabs Scribe"
119→    }
120→
121→    fn is_configured(&self) -> bool {
122→        self.api_key.is_some()
123→    }
124→
125→    async fn transcribe(&self, request: TranscribeRequest) -> Result<Transcript> {
126→        let api_key = self.get_api_key()?;
127→
128→        // Build multipart form
129→        let file_ext = Self::file_extension(request.format);
130→        let file_part = Part::bytes(request.audio.to_vec())
131→            .file_name(format!("audio.{file_ext}"))
132→            .mime_str(request.format.mime_type())
133→            .context("invalid mime type")?;
134→
135→        let mut form = Form::new()
136→            .part("file", file_part)
137→            .text("model_id", self.model.clone());
138→
139→        // Use request language if provided, otherwise fall back to configured language
140→        if let Some(language) = request.language.as_ref().or(self.language.as_ref()) {
141→            form = form.text("language", language.clone());
142→        }
143→
144→        // Add context text for terminology hints (Scribe v2 feature)
145→        if let Some(prompt) = request.prompt.as_ref() {
146→            form = form.text("context_text", prompt.clone());
147→        }
148→
149→        let url = format!("{}/speech-to-text", self.base_url);
150→
151→        let response = self
152→            .client
153→            .post(&url)
154→            .header("xi-api-key", api_key.expose_secret())
155→            .multipart(form)
156→            .send()
157→            .await
158→            .context("failed to send ElevenLabs transcription request")?;
159→
160→        if !response.status().is_success() {
161→            let status = response.status();
162→            let body = response.text().await.unwrap_or_default();
163→            return Err(anyhow!(
164→                "ElevenLabs transcription request failed: {} - {}",
165→                status,
166→                body
167→            ));
168→        }
169→
170→        let el_response: ElevenLabsResponse = response
171→            .json()
172→            .await
173→            .context("failed to parse ElevenLabs response")?;
174→
175→        Ok(Transcript {
176→            text: el_response.text,
177→            language: el_response.language_code,
178→            confidence: el_response.language_probability,
179→            duration_seconds: None, // Not provided by ElevenLabs API
180→            words: el_response.words.map(|words| {
181→                words
182→                    .into_iter()
183→                    .map(|w| Word {
184→                        word: w.text,
185→                        start: w.start,
186→                        end: w.end,
187→                    })
188→                    .collect()
189→            }),
190→        })
191→    }
192→}
193→
194→// ── API Types ──────────────────────────────────────────────────────────────
195→
196→#[derive(Debug, Deserialize)]
197→struct ElevenLabsResponse {
198→    text: String,
199→    #[serde(default)]
200→    language_code: Option<String>,
201→    #[serde(default)]
202→    language_probability: Option<f32>,
203→    #[serde(default)]
204→    words: Option<Vec<ElevenLabsWord>>,
205→}
206→
207→#[derive(Debug, Deserialize)]
208→struct ElevenLabsWord {
209→    text: String,
210→    start: f32,
211→    end: f32,
212→}
213→
214→#[allow(clippy::unwrap_used, clippy::expect_used)]
215→#[cfg(test)]
216→mod tests {
217→    use {super::*, bytes::Bytes};
218→
219→    #[test]
220→    fn test_provider_metadata() {
221→        let provider = ElevenLabsStt::new(None);
222→        assert_eq!(provider.id(), "elevenlabs");
223→        assert_eq!(provider.name(), "ElevenLabs Scribe");
224→        assert!(!provider.is_configured());
225→
226→        let configured = ElevenLabsStt::new(Some(Secret::new("test-key".into())));
227→        assert!(configured.is_configured());
228→    }
229→
230→    #[test]
231→    fn test_debug_redacts_api_key() {
232→        let provider = ElevenLabsStt::new(Some(Secret::new("super-secret-key".into())));
233→        let debug_output = format!("{:?}", provider);
234→        assert!(debug_output.contains("[REDACTED]"));
235→        assert!(!debug_output.contains("super-secret-key"));
236→    }
237→
238→    #[test]
239→    fn test_with_options() {
240→        let provider = ElevenLabsStt::with_options(
241→            Some(Secret::new("key".into())),
242→            Some("scribe_v2".into()),
243→            Some("en".into()),
244→        );
245→        assert_eq!(provider.model, "scribe_v2");
246→        assert_eq!(provider.language, Some("en".into()));
247→    }
248→
249→    #[tokio::test]
250→    async fn test_transcribe_without_api_key() {
251→        let provider = ElevenLabsStt::new(None);
252→        let request = TranscribeRequest {
253→            audio: Bytes::from_static(b"fake audio"),
254→            format: AudioFormat::Mp3,
255→            language: None,
256→            prompt: None,
257→        };
258→
259→        let result = provider.transcribe(request).await;
260→        assert!(result.is_err());
261→        assert!(result.unwrap_err().to_string().contains("not configured"));
262→    }
263→
264→    #[test]
265→    fn test_elevenlabs_response_parsing() {
266→        let json = r#"{
267→            "text": "Hello, how are you?",
268→            "language_code": "en",
269→            "language_probability": 0.95,
270→            "words": [
271→                {"text": "Hello", "start": 0.0, "end": 0.5, "type": "word"},
272→                {"text": ",", "start": 0.5, "end": 0.55, "type": "punctuation"},
273→                {"text": "how", "start": 0.6, "end": 0.8, "type": "word"}
274→            ]
275→        }"#;
276→
277→        let response: ElevenLabsResponse = serde_json::from_str(json).unwrap();
278→        assert_eq!(response.text, "Hello, how are you?");
279→        assert_eq!(response.language_code, Some("en".into()));
280→        assert_eq!(response.language_probability, Some(0.95));
281→        assert_eq!(response.words.as_ref().unwrap().len(), 3);
282→    }
283→
284→    #[test]
285→    fn test_elevenlabs_response_minimal() {
286→        let json = r#"{
287→            "text": "Hello"
288→        }"#;
289→        let response: ElevenLabsResponse = serde_json::from_str(json).unwrap();
290→        assert_eq!(response.text, "Hello");
291→        assert!(response.language_code.is_none());
292→        assert!(response.language_probability.is_none());
293→        assert!(response.words.is_none());
294→    }
295→
296→    #[test]
