 29→/// Request to transcribe audio to text.
 30→#[derive(Debug, Clone)]
 31→pub struct TranscribeRequest {
 32→    /// Raw audio data.
 33→    pub audio: Bytes,
 34→    /// Audio format.
 35→    pub format: AudioFormat,
 36→    /// Language hint (ISO 639-1 code, e.g., "en", "es", "fr").
 37→    pub language: Option<String>,
 38→    /// Optional prompt to guide transcription (context, terminology).
 39→    pub prompt: Option<String>,
 40→}
 41→
 42→/// Transcription result.
 43→#[derive(Debug, Clone, Serialize, Deserialize)]
 44→pub struct Transcript {
 45→    /// Transcribed text.
 46→    pub text: String,
 47→    /// Detected language (ISO 639-1 code).
 48→    pub language: Option<String>,
 49→    /// Confidence score (0.0 - 1.0).
 50→    pub confidence: Option<f32>,
 51→    /// Duration of audio in seconds.
 52→    pub duration_seconds: Option<f32>,
 53→    /// Word-level timestamps (if available).
 54→    pub words: Option<Vec<Word>>,
 55→}
 56→
 57→/// Word with timing information.
 58→#[derive(Debug, Clone, Serialize, Deserialize)]
 59→pub struct Word {
 60→    /// The word text.
 61→    pub word: String,
 62→    /// Start time in seconds.
 63→    pub start: f32,
 64→    /// End time in seconds.
 65→    pub end: f32,
 66→}
 67→
 68→/// Speech-to-Text provider trait.
 69→///
 70→/// Implementations provide audio transcription using various services.
 71→#[async_trait]
 72→pub trait SttProvider: Send + Sync {
 73→    /// Provider identifier (e.g., "whisper").
 74→    fn id(&self) -> &'static str;
 75→
 76→    /// Human-readable provider name.
 77→    fn name(&self) -> &'static str;
 78→
 79→    /// Check if the provider is configured and ready.
 80→    fn is_configured(&self) -> bool;
 81→
 82→    /// Transcribe audio to text.
 83→    async fn transcribe(&self, request: TranscribeRequest) -> Result<Transcript>;
 84→}
