 66→// ── TTS Service ─────────────────────────────────────────────────────────────
 67→
 68→/// Live TTS service that delegates to voice providers.
 69→/// Reads fresh config on each operation to pick up changes.
 70→#[cfg(feature = "voice")]
 71→pub struct LiveTtsService {
 72→    _marker: std::marker::PhantomData<()>,
 73→}
 74→
 75→#[cfg(feature = "voice")]
 76→impl std::fmt::Debug for LiveTtsService {
 77→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 78→        f.debug_struct("LiveTtsService").finish()
 79→    }
 80→}
 81→
 82→#[cfg(feature = "voice")]
 83→impl LiveTtsService {
 84→    /// Create a new TTS service. Config is read fresh on each operation.
 85→    pub fn new(_config: TtsConfig) -> Self {
 86→        Self {
 87→            _marker: std::marker::PhantomData,
 88→        }
 89→    }
 90→
 91→    /// Create from environment variables (same as new, config read on demand).
 92→    pub fn from_env() -> Self {
 93→        Self {
 94→            _marker: std::marker::PhantomData,
 95→        }
 96→    }
 97→
 98→    /// Load fresh TTS config from disk.
 99→    fn load_config() -> TtsConfig {
100→        let cfg = moltis_config::discover_and_load();
101→        TtsConfig {
102→            enabled: cfg.voice.tts.enabled,
103→            provider: cfg.voice.tts.provider.clone(),
104→            auto: moltis_voice::TtsAutoMode::Off,
105→            max_text_length: 8000,
106→            elevenlabs: moltis_voice::ElevenLabsConfig {
107→                api_key: cfg.voice.tts.elevenlabs.api_key.clone(),
108→                voice_id: cfg.voice.tts.elevenlabs.voice_id.clone(),
109→                model: cfg.voice.tts.elevenlabs.model.clone(),
110→                stability: None,
111→                similarity_boost: None,
112→            },
113→            openai: moltis_voice::OpenAiTtsConfig {
114→                api_key: resolve_openai_key(cfg.voice.tts.openai.api_key.as_ref(), &cfg),
115→                voice: cfg.voice.tts.openai.voice.clone(),
116→                model: cfg.voice.tts.openai.model.clone(),
117→                speed: None,
118→            },
119→            google: moltis_voice::GoogleTtsConfig {
120→                api_key: cfg.voice.tts.google.api_key.clone(),
121→                voice: cfg.voice.tts.google.voice.clone(),
122→                language_code: cfg.voice.tts.google.language_code.clone(),
123→                speaking_rate: cfg.voice.tts.google.speaking_rate,
124→                pitch: cfg.voice.tts.google.pitch,
125→            },
126→            piper: moltis_voice::PiperTtsConfig {
127→                binary_path: cfg.voice.tts.piper.binary_path.clone(),
128→                model_path: cfg.voice.tts.piper.model_path.clone(),
129→                config_path: None,
130→                speaker_id: None,
131→                length_scale: None,
132→            },
133→            coqui: moltis_voice::CoquiTtsConfig {
134→                endpoint: cfg.voice.tts.coqui.endpoint.clone(),
135→                model: cfg.voice.tts.coqui.model.clone(),
136→                speaker: None,
137→                language: None,
138→            },
139→        }
140→    }
141→
142→    /// Create a provider on-demand from fresh config.
143→    fn create_provider(provider_id: TtsProviderId) -> Option<Box<dyn TtsProvider + Send + Sync>> {
144→        let config = Self::load_config();
145→        match provider_id {
146→            TtsProviderId::ElevenLabs => config.elevenlabs.api_key.as_ref().map(|key| {
147→                Box::new(ElevenLabsTts::with_defaults(
148→                    Some(key.clone()),
149→                    config.elevenlabs.voice_id.clone(),
150→                    config.elevenlabs.model.clone(),
151→                )) as Box<dyn TtsProvider + Send + Sync>
152→            }),
153→            TtsProviderId::OpenAi => config.openai.api_key.as_ref().map(|key| {
154→                Box::new(OpenAiTts::with_defaults(
155→                    Some(key.clone()),
156→                    config.openai.voice.clone(),
157→                    config.openai.model.clone(),
158→                )) as Box<dyn TtsProvider + Send + Sync>
159→            }),
160→            TtsProviderId::Google => config.google.api_key.as_ref().map(|_| {
161→                Box::new(GoogleTts::new(&config.google)) as Box<dyn TtsProvider + Send + Sync>
162→            }),
163→            TtsProviderId::Piper => {
164→                let piper = PiperTts::new(&config.piper);
165→                if piper.is_configured() {
166→                    Some(Box::new(piper) as Box<dyn TtsProvider + Send + Sync>)
167→                } else {
168→                    None
169→                }
170→            },
171→            TtsProviderId::Coqui => {
172→                let coqui = CoquiTts::new(&config.coqui);
173→                if coqui.is_configured() {
174→                    Some(Box::new(coqui) as Box<dyn TtsProvider + Send + Sync>)
175→                } else {
176→                    None
177→                }
178→            },
179→        }
180→    }
181→
182→    /// List all providers with their configuration status.
183→    fn list_providers() -> Vec<(TtsProviderId, bool)> {
184→        let config = Self::load_config();
185→        vec![
186→            (
187→                TtsProviderId::ElevenLabs,
188→                config.elevenlabs.api_key.is_some(),
189→            ),
190→            (TtsProviderId::OpenAi, config.openai.api_key.is_some()),
191→            (TtsProviderId::Google, config.google.api_key.is_some()),
192→            (TtsProviderId::Piper, config.piper.model_path.is_some()),
193→            (TtsProviderId::Coqui, true), // Always available if server running
194→        ]
195→    }
196→
197→    /// Resolve the active provider: explicit config value, or first configured.
198→    fn resolve_provider(config_provider: &str) -> Option<TtsProviderId> {
199→        if !config_provider.is_empty() {
200→            return TtsProviderId::parse(config_provider);
201→        }
202→        // Auto-select: first configured provider
203→        Self::list_providers()
204→            .into_iter()
205→            .find(|(_, configured)| *configured)
206→            .map(|(id, _)| id)
207→    }
208→
209→    /// Parse provider from JSON params, falling back to config/auto-select.
210→    fn resolve_from_params(
211→        params: &Value,
212→        config_provider: &str,
213→    ) -> Result<TtsProviderId, ServiceError> {
214→        match params.get("provider").and_then(|v| v.as_str()) {
215→            Some(s) => TtsProviderId::parse(s)
216→                .ok_or_else(|| ServiceError::message(format!("unknown TTS provider '{s}'"))),
217→            None => Self::resolve_provider(config_provider)
218→                .ok_or_else(|| ServiceError::message("no TTS provider configured")),
219→        }
220→    }
221→}
222→
223→#[cfg(feature = "voice")]
224→#[async_trait]
225→impl TtsService for LiveTtsService {
226→    async fn status(&self) -> ServiceResult {
227→        let config = Self::load_config();
228→        let providers = Self::list_providers();
229→        let any_configured = providers.iter().any(|(_, configured)| *configured);
230→        let resolved = Self::resolve_provider(&config.provider);
231→
232→        Ok(json!({
233→            "enabled": config.enabled && any_configured,
234→            "provider": resolved.map(|p| p.to_string()).unwrap_or_default(),
235→            "auto": format!("{:?}", config.auto).to_lowercase(),
236→            "maxTextLength": config.max_text_length,
237→            "configured": any_configured,
238→        }))
239→    }
240→
241→    async fn providers(&self) -> ServiceResult {
242→        let providers: Vec<_> = Self::list_providers()
243→            .into_iter()
244→            .map(|(id, configured)| {
245→                json!({
246→                    "id": id,  // Uses serde serialization for consistent IDs
247→                    "name": id.name(),
248→                    "configured": configured,
249→                })
250→            })
251→            .collect();
252→
253→        Ok(json!(providers))
254→    }
255→
256→    async fn enable(&self, params: Value) -> ServiceResult {
257→        let config = Self::load_config();
258→        let provider_id = Self::resolve_from_params(&params, &config.provider)?;
259→
260→        if Self::create_provider(provider_id).is_none() {
261→            return Err(format!("provider '{}' not configured", provider_id).into());
262→        }
263→
264→        // Update config file
265→        moltis_config::update_config(|cfg| {
266→            cfg.voice.tts.provider = provider_id.to_string();
267→            cfg.voice.tts.enabled = true;
268→        })
269→        .map_err(|e| format!("failed to update config: {}", e))?;
270→
271→        debug!("TTS enabled with provider: {}", provider_id);
272→
273→        Ok(json!({
274→            "enabled": true,
275→            "provider": provider_id,  // Uses serde serialization
276→        }))
277→    }
278→
279→    async fn disable(&self) -> ServiceResult {
280→        moltis_config::update_config(|cfg| {
281→            cfg.voice.tts.enabled = false;
282→        })
283→        .map_err(|e| format!("failed to update config: {}", e))?;
284→
285→        debug!("TTS disabled");
286→
287→        Ok(json!({ "enabled": false }))
288→    }
289→
290→    async fn convert(&self, params: Value) -> ServiceResult {
291→        let config = Self::load_config();
292→
293→        if !config.enabled {
294→            warn!("TTS convert called but TTS is not enabled");
295→            return Err("TTS is not enabled".into());
296→        }
297→
298→        let text = params
299→            .get("text")
300→            .and_then(|v| v.as_str())
301→            .ok_or("missing 'text' parameter")?;
302→
303→        if text.len() > config.max_text_length {
304→            return Err(format!(
305→                "text exceeds max length ({} > {})",
306→                text.len(),
307→                config.max_text_length
308→            )
309→            .into());
310→        }
311→
312→        let provider_id = Self::resolve_from_params(&params, &config.provider)?;
313→
314→        info!(
315→            provider = %provider_id,
316→            text_len = text.len(),
317→            "TTS convert request"
318→        );
319→
320→        let provider = Self::create_provider(provider_id)
321→            .ok_or_else(|| format!("provider '{}' not configured", provider_id))?;
322→
323→        // Strip SSML tags for providers that don't support them natively
324→        let text = if provider.supports_ssml() {
325→            text.to_string()
326→        } else {
327→            strip_ssml_tags(text).into_owned()
328→        };
329→
330→        let format = params
331→            .get("format")
332→            .and_then(|v| v.as_str())
333→            .map(AudioFormat::from_short_name)
334→            .unwrap_or(AudioFormat::Mp3);
335→
336→        let request = SynthesizeRequest {
337→            text,
338→            voice_id: params
339→                .get("voiceId")
340→                .and_then(|v| v.as_str())
341→                .map(String::from),
342→            model: params
343→                .get("model")
344→                .and_then(|v| v.as_str())
345→                .map(String::from),
346→            output_format: format,
347→            speed: params
348→                .get("speed")
349→                .and_then(|v| v.as_f64())
350→                .map(|v| v as f32),
351→            stability: params
352→                .get("stability")
353→                .and_then(|v| v.as_f64())
354→                .map(|v| v as f32),
355→            similarity_boost: params
356→                .get("similarityBoost")
357→                .and_then(|v| v.as_f64())
358→                .map(|v| v as f32),
359→        };
360→
361→        let output = provider.synthesize(request).await.map_err(|e| {
362→            warn!(provider = %provider_id, error = %e, "TTS synthesis failed");
363→            format!("TTS synthesis failed: {}", e)
364→        })?;
365→
366→        info!(
367→            provider = %provider_id,
368→            format = ?output.format,
369→            audio_bytes = output.data.len(),
370→            duration_ms = ?output.duration_ms,
371→            "TTS synthesis complete"
372→        );
373→
374→        let audio_base64 = base64::engine::general_purpose::STANDARD.encode(&output.data);
375→
376→        Ok(json!({
377→            "audio": audio_base64,
378→            "format": format!("{:?}", output.format).to_lowercase(),
379→            "mimeType": output.format.mime_type(),
380→            "durationMs": output.duration_ms,
381→            "size": output.data.len(),
382→        }))
383→    }
384→
385→    async fn set_provider(&self, params: Value) -> ServiceResult {
386→        let provider_str = params
387→            .get("provider")
388→            .and_then(|v| v.as_str())
389→            .ok_or("missing 'provider' parameter")?;
390→
391→        let provider_id = TtsProviderId::parse(provider_str)
392→            .ok_or_else(|| format!("unknown TTS provider '{}'", provider_str))?;
393→
394→        if Self::create_provider(provider_id).is_none() {
395→            return Err(format!("provider '{}' not configured", provider_id).into());
396→        }
397→
398→        moltis_config::update_config(|cfg| {
399→            cfg.voice.tts.provider = provider_id.to_string();
400→        })
401→        .map_err(|e| format!("failed to update config: {}", e))?;
402→
403→        debug!("TTS provider set to: {}", provider_id);
404→
405→        Ok(json!({
406→            "provider": provider_id,  // Uses serde serialization
407→        }))
408→    }
409→}
