652→#[cfg(feature = "voice")]
653→#[async_trait]
654→impl SttService for LiveSttService {
655→    async fn status(&self) -> ServiceResult {
656→        let cfg = moltis_config::discover_and_load();
657→        let providers = Self::list_providers();
658→        let any_configured = providers.iter().any(|(_, configured)| *configured);
659→        let resolved = Self::resolve_provider(cfg.voice.stt.provider);
660→
661→        Ok(json!({
662→            "enabled": any_configured,
663→            "provider": resolved.map(|p| p.to_string()).unwrap_or_default(),
664→            "configured": any_configured,
665→        }))
666→    }
667→
668→    async fn providers(&self) -> ServiceResult {
669→        let providers: Vec<_> = Self::list_providers()
670→            .into_iter()
671→            .map(|(id, configured)| {
672→                json!({
673→                    "id": id,  // Uses serde serialization for consistent IDs
674→                    "name": id.name(),
675→                    "configured": configured,
676→                })
677→            })
678→            .collect();
679→
680→        Ok(json!(providers))
681→    }
682→
683→    async fn transcribe(&self, params: Value) -> ServiceResult {
684→        let audio_base64 = params
685→            .get("audio")
686→            .and_then(|v| v.as_str())
687→            .ok_or("missing 'audio' parameter (base64-encoded)")?;
688→
689→        let audio_data = base64::engine::general_purpose::STANDARD
690→            .decode(audio_base64)
691→            .map_err(|e| format!("invalid base64 audio: {}", e))?;
692→
693→        let format_str = params
694→            .get("format")
695→            .and_then(|v| v.as_str())
696→            .unwrap_or("mp3");
697→
698→        self.transcribe_bytes(
699→            audio_data.into(),
700→            format_str,
701→            params.get("provider").and_then(|v| v.as_str()),
702→            params.get("language").and_then(|v| v.as_str()),
703→            params.get("prompt").and_then(|v| v.as_str()),
704→        )
705→        .await
706→    }
707→
708→    async fn transcribe_bytes(
709→        &self,
710→        audio: bytes::Bytes,
711→        format: &str,
712→        provider: Option<&str>,
713→        language: Option<&str>,
714→        prompt: Option<&str>,
715→    ) -> ServiceResult {
716→        let cfg = moltis_config::discover_and_load();
717→
718→        let provider_id = match provider {
719→            Some(s) => {
720→                SttProviderId::parse(s).ok_or_else(|| format!("unknown STT provider '{s}'"))?
721→            },
722→            None => Self::resolve_provider(cfg.voice.stt.provider)
723→                .ok_or_else(|| "no STT provider configured".to_string())?,
724→        };
725→
726→        let stt_provider: Box<dyn SttProvider + Send + Sync> =
727→            Self::create_provider(provider_id)
728→                .ok_or_else(|| format!("STT provider '{}' not configured", provider_id))?;
729→
730→        let request = TranscribeRequest {
731→            audio,
732→            format: AudioFormat::from_short_name(format),
733→            language: language.map(String::from),
734→            prompt: prompt.map(String::from),
735→        };
736→
737→        let transcript = stt_provider
738→            .transcribe(request)
739→            .await
740→            .map_err(|e| format!("transcription failed: {}", e))?;
741→
742→        Ok(json!({
743→            "text": transcript.text,
744→            "language": transcript.language,
745→            "confidence": transcript.confidence,
746→            "durationSeconds": transcript.duration_seconds,
747→            "words": transcript.words,
748→        }))
749→    }
750→
751→    async fn set_provider(&self, params: Value) -> ServiceResult {
752→        let provider_str = params
753→            .get("provider")
754→            .and_then(|v| v.as_str())
755→            .ok_or("missing 'provider' parameter")?;
756→
757→        let provider_id = SttProviderId::parse(provider_str)
758→            .ok_or_else(|| format!("unknown STT provider '{}'", provider_str))?;
759→
760→        if Self::create_provider(provider_id).is_none() {
761→            return Err(format!("provider '{}' not configured", provider_id).into());
762→        }
763→
764→        // Update config file
765→        moltis_config::update_config(|cfg| {
766→            cfg.voice.stt.provider = Some(provider_id.into_voice_stt_provider());
767→        })
768→        .map_err(|e| format!("failed to update config: {}", e))?;
769→
770→        debug!("STT provider set to: {}", provider_id);
771→
772→        Ok(json!({
773→            "provider": provider_id,  // Uses serde serialization
774→        }))
775→    }
776→}
