 1→// ── Shared identity RPC wrappers and validation ───────────────
 2→//
 3→// Used by page-settings.js and onboarding-view.js.
 4→
 5→import { sendRpc } from "./helpers.js";
 6→
 7→/**
 8→ * Validate identity fields before submission.
 9→ * @param {string} name - agent name
10→ * @param {string} userName - user's name
11→ * @returns {{ valid: true } | { valid: false, error: string }}
12→ */
13→export function validateIdentityFields(name, userName) {
14→	if (!(name.trim() || userName.trim())) {
15→		return { valid: false, error: "Agent name and your name are required." };
16→	}
17→	if (!name.trim()) {
18→		return { valid: false, error: "Agent name is required." };
19→	}
20→	if (!userName.trim()) {
21→		return { valid: false, error: "Your name is required." };
22→	}
23→	return { valid: true };
24→}
25→
26→function isMissingMethodError(res) {
27→	var message = res?.error?.message;
28→	if (typeof message !== "string") return false;
29→	var lower = message.toLowerCase();
30→	return lower.includes("method") && (lower.includes("not found") || lower.includes("unknown"));
31→}
32→
33→/**
34→ * Update agent identity fields.
35→ * @param {object} fields - any subset of { name, emoji, theme, soul, user_name, user_timezone }
36→ * @param {{ agentId?: string }} [options] - optional explicit agent target
37→ * @returns {Promise} RPC response
38→ */
39→export function updateIdentity(fields, options = {}) {
40→	var agentId = options.agentId;
41→	if (!agentId) {
42→		return sendRpc("agent.identity.update", fields);
43→	}
44→	var params = { ...fields, agent_id: agentId };
45→	return sendRpc("agents.identity.update", params).then((res) => {
46→		if (res?.ok || !isMissingMethodError(res)) return res;
47→		return sendRpc("agent.identity.update", fields);
48→	});
49→}
