334→			// Safe: body_html is server-rendered trusted HTML from the Rust gateway (SKILL.md → pulldown-cmark)
335→			bodyRef.current.textContent = "";
336→			var tpl = document.createElement("template");
337→			tpl.innerHTML = d.body_html; // eslint-disable-line no-unsanitized/property
338→			bodyRef.current.appendChild(tpl.content);
339→			bodyRef.current.querySelectorAll("a").forEach((a) => {
340→				a.setAttribute("target", "_blank");
341→				a.setAttribute("rel", "noopener");
342→			});
343→		}
344→		// Scroll only on first render (panel just opened), not when switching skills.
345→		if (panelRef.current && !didScroll.current) {
346→			didScroll.current = true;
347→			var el = panelRef.current;
348→			var scrollParent = el.parentElement;
349→			while (
350→				scrollParent &&
351→				getComputedStyle(scrollParent).overflowY !== "auto" &&
352→				getComputedStyle(scrollParent).overflowY !== "scroll"
353→			) {
354→				scrollParent = scrollParent.parentElement;
355→			}
356→			if (scrollParent) {
357→				var panelTop =
358→					el.getBoundingClientRect().top - scrollParent.getBoundingClientRect().top + scrollParent.scrollTop;
359→				scrollParent.scrollTo({ top: panelTop, behavior: "smooth" });
360→			}
361→		}
362→	}, [d?.body_html]);
363→
364→	if (!d) return null;
365→
366→	var isDisc = d.source === "personal" || d.source === "project";
367→	var needsTrust = !isDisc && d.trusted === false;
368→	var isProtected = isDisc && d.protected === true;
369→
370→	function doToggle() {
371→		actionBusy.value = true;
372→		var method = d.enabled ? "skills.skill.disable" : "skills.skill.enable";
373→		sendRpc(method, { source: props.repoSource, skill: d.name }).then((r) => {
374→			actionBusy.value = false;
375→			if (r?.ok) {
376→				if (isDisc) onClose();
