379→			} else {
380→				showToast(`Failed: ${r?.error || "unknown error"}`, "error");
381→			}
382→		});
383→	}
384→
385→	function onToggle() {
386→		if (!S.connected) return;
387→		if (actionBusy.value) return;
388→		if (isProtected) {
389→			showToast(`Skill ${d.name} is protected and cannot be deleted from UI`, "error");
390→			return;
391→		}
392→		if (!d.enabled && needsTrust) {
393→			requestConfirm(`Trust skill "${d.name}" from ${props.repoSource}?`, {
394→				confirmLabel: "Trust & Enable",
395→			}).then((yes) => {
396→				if (!yes) return;
397→				actionBusy.value = true;
398→				sendRpc("skills.skill.trust", { source: props.repoSource, skill: d.name }).then((res) => {
399→					if (!res?.ok) {
400→						actionBusy.value = false;
401→						showToast(`Trust failed: ${res?.error || "unknown error"}`, "error");
402→						return;
403→					}
404→					doToggle();
405→				});
406→			});
407→			return;
408→		}
409→		if (isDisc && d.enabled) {
410→			requestConfirm(`Delete skill "${d.name}"? This removes the SKILL.md file.`, {
411→				confirmLabel: "Delete",
412→				danger: true,
413→			}).then((yes) => {
414→				if (yes) doToggle();
415→			});
416→			return;
417→		}
418→		doToggle();
419→	}
