491→	var searchResults = useSignal([]);
492→	var allSkills = useSignal([]);
493→	var searching = useSignal(false);
494→	var activeDetail = useSignal(null);
495→	var detailLoading = useSignal(false);
496→	var searchTimer = useRef(null);
497→	var removingRepo = useSignal(false);
498→	var isOrphan = repo.orphaned === true || String(repo.source || "").startsWith("orphan:");
499→	var sourceLabel = isOrphan ? repo.repo_name : repo.source;
500→
501→	var href = isOrphan ? null : /^https?:\/\//.test(repo.source) ? repo.source : `https://github.com/${repo.source}`;
502→
503→	function toggleExpand() {
504→		var willExpand = !expanded.value;
505→		expanded.value = willExpand;
506→		if (willExpand && !isOrphan && allSkills.value.length === 0) {
507→			searching.value = true;
508→			searchSkills(repo.source, "").then((results) => {
509→				allSkills.value = results;
510→				searching.value = false;
511→			});
512→		}
513→	}
514→
515→	function onSearchInput(e) {
516→		if (isOrphan) return;
517→		var q = e.target.value;
518→		searchQuery.value = q;
519→		activeDetail.value = null;
520→		if (searchTimer.current) clearTimeout(searchTimer.current);
521→		if (!q.trim()) {
522→			searchResults.value = [];
523→			return;
524→		}
525→		searching.value = true;
526→		searchTimer.current = setTimeout(() => {
527→			searchSkills(repo.source, q.trim()).then((results) => {
528→				searchResults.value = results;
529→				searching.value = false;
530→			});
531→		}, 200);
532→	}
533→
534→	var displayedSkills = searchQuery.value.trim() ? searchResults.value : allSkills.value;
535→
536→	function loadDetail(skill) {
537→		detailLoading.value = true;
538→		sendRpc("skills.skill.detail", {
539→			source: repo.source,
540→			skill: skill.name,
541→		}).then((res) => {
542→			detailLoading.value = false;
543→			if (res?.ok) {
544→				activeDetail.value = res.payload || {};
545→			} else {
546→				showToast(`Failed to load: ${res?.error || "unknown"}`, "error");
547→			}
548→		});
549→	}
550→
551→	function removeRepo(e) {
552→		e.stopPropagation();
553→		if (!S.connected || removingRepo.value) return;
554→		removingRepo.value = true;
555→		sendRpc("skills.repos.remove", { source: repo.source }).then((res) => {
556→			removingRepo.value = false;
557→			if (res?.ok) fetchAll();
558→			else showToast(`Failed: ${res?.error || "unknown error"}`, "error");
559→		});
560→	}
561→
562→	return html`<div class="skills-repo-card">
563→    <div class="skills-repo-header" onClick=${toggleExpand}>
564→      <div style="display:flex;align-items:center;gap:8px">
565→        <span style=${{ fontSize: ".65rem", color: "var(--muted)", transition: "transform .15s", transform: expanded.value ? "rotate(90deg)" : "" }}>\u25B6</span>
566→        ${
567→					href
568→						? html`<a href=${href} target="_blank" rel="noopener noreferrer" onClick=${(e) => {
569→								e.stopPropagation();
570→							}}
571→           style="font-family:var(--font-mono);font-size:.82rem;font-weight:500;color:var(--text-strong);text-decoration:none">${sourceLabel}</a>`
572→						: html`<span style="font-family:var(--font-mono);font-size:.82rem;font-weight:500;color:var(--text-strong)">${sourceLabel}</span>`
573→				}
574→        <span style="font-size:.72rem;color:var(--muted)">${repo.enabled_count}/${repo.skill_count} enabled</span>
575→				${repo.commit_sha && html`<span style="font-size:.68rem;color:var(--muted)">sha ${shortSha(repo.commit_sha)}</span>`}
576→				${repo.drifted && html`<span style="font-size:.64rem;padding:1px 6px;border-radius:9999px;background:var(--warning, #c77d00);color:#fff;font-weight:500">source changed</span>`}
577→				${isOrphan && html`<span style="font-size:.64rem;padding:1px 6px;border-radius:9999px;background:var(--warning, #c77d00);color:#fff;font-weight:500">orphaned on disk</span>`}
578→      </div>
579→      <button class="provider-btn provider-btn-sm provider-btn-danger" disabled=${removingRepo.value} onClick=${removeRepo}>${removingRepo.value ? "Removing..." : "Remove"}</button>
580→    </div>
581→    ${
582→			expanded.value &&
583→			html`<div class="skills-repo-detail" style="display:block">
584→      <div style="margin-bottom:8px">
585→        <input type="text" placeholder=${isOrphan ? "Orphaned repo: reinstall to restore metadata" : `Search skills in ${repo.source}\u2026`} value=${searchQuery.value} disabled=${isOrphan}
586→          onInput=${onSearchInput}
587→          style="width:100%;padding:6px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);background:var(--surface);color:var(--text);font-size:.8rem;font-family:var(--font-mono);box-sizing:border-box" />
