607→              </div>
608→            </div>`,
609→					)}
610→        </div>`
611→			}
612→      ${
613→				!activeDetail.value &&
614→				displayedSkills.length === 0 &&
615→				!searching.value &&
616→				html`<div style="padding:8px 10px;color:var(--muted);font-size:.78rem">${searchQuery.value.trim() ? "No matching skills." : ""}</div>`
