619→      ${detailLoading.value && html`<div style="color:var(--muted);font-size:.8rem">Loading\u2026</div>`}
620→      ${
621→				activeDetail.value &&
622→				html`<${SkillDetail}
623→        detail=${activeDetail.value}
624→        repoSource=${repo.source}
625→        onClose=${() => {
