695→		if (isDiscovered(skill) && skill.protected === true) {
696→			showToast(`Skill ${skill.name} is protected and cannot be deleted from UI`, "error");
697→			return;
698→		}
699→		if (isDiscovered(skill)) {
700→			requestConfirm(`Delete skill "${skill.name}"? This removes the SKILL.md file.`, {
701→				confirmLabel: "Delete",
702→				danger: true,
703→			}).then((yes) => {
