718→		if (!source) return;
719→		detailLoading.value = true;
720→		sendRpc("skills.skill.detail", { source: source, skill: skill.name }).then((res) => {
721→			detailLoading.value = false;
722→			if (res?.ok) {
723→				activeDetail.value = res.payload || {};
724→			} else {
725→				showToast(`Failed to load: ${res?.error || "unknown"}`, "error");
726→			}
727→		});
728→	}
729→
730→	return html`<div class="skills-section">
731→    <h3 class="skills-section-title">Enabled Skills</h3>
