  1→//! Agent tools for creating, updating, and deleting personal skills at runtime.
  2→//! Skills are written to `<data_dir>/skills/<name>/SKILL.md` (Personal source).
  3→
  4→use std::path::{Path, PathBuf};
  5→
  6→use {
  7→    async_trait::async_trait,
  8→    moltis_agents::tool_registry::AgentTool,
  9→    serde_json::{Value, json},
 10→};
 11→
 12→use crate::error::Error;
 13→
 14→/// Tool that creates a new personal skill in `<data_dir>/skills/`.
 15→pub struct CreateSkillTool {
 16→    data_dir: PathBuf,
 17→}
 18→
 19→impl CreateSkillTool {
 20→    pub fn new(data_dir: PathBuf) -> Self {
 21→        Self { data_dir }
 22→    }
 23→
 24→    fn skills_dir(&self) -> PathBuf {
 25→        self.data_dir.join("skills")
 26→    }
 27→}
 28→
 29→#[async_trait]
 30→impl AgentTool for CreateSkillTool {
 31→    fn name(&self) -> &str {
 32→        "create_skill"
 33→    }
 34→
 35→    fn description(&self) -> &str {
 36→        "Create a new personal skill. Writes a SKILL.md file to <data_dir>/skills/<name>/. \
 37→         This is persistent workspace storage (not sandbox ~/skills). \
 38→         The skill will be available on the next message automatically."
 39→    }
 40→
 41→    fn parameters_schema(&self) -> Value {
 42→        json!({
 43→            "type": "object",
 44→            "required": ["name", "description", "body"],
 45→            "properties": {
 46→                "name": {
 47→                    "type": "string",
 48→                    "description": "Skill name (lowercase, hyphens, 1-64 chars)"
 49→                },
 50→                "description": {
 51→                    "type": "string",
 52→                    "description": "Short human-readable description"
 53→                },
 54→                "body": {
 55→                    "type": "string",
 56→                    "description": "Markdown instructions for the skill"
 57→                },
 58→                "allowed_tools": {
 59→                    "type": "array",
 60→                    "items": { "type": "string" },
 61→                    "description": "Optional list of tools this skill may use"
 62→                }
 63→            }
 64→        })
 65→    }
 66→
 67→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 68→        let name = params
 69→            .get("name")
 70→            .and_then(|v| v.as_str())
 71→            .ok_or_else(|| Error::message("missing 'name'"))?;
 72→        let description = params
 73→            .get("description")
 74→            .and_then(|v| v.as_str())
 75→            .ok_or_else(|| Error::message("missing 'description'"))?;
 76→        let body = params
 77→            .get("body")
 78→            .and_then(|v| v.as_str())
 79→            .ok_or_else(|| Error::message("missing 'body'"))?;
 80→        let allowed_tools: Vec<String> = params
 81→            .get("allowed_tools")
 82→            .and_then(|v| v.as_array())
 83→            .map(|arr| {
 84→                arr.iter()
 85→                    .filter_map(|v| v.as_str().map(String::from))
 86→                    .collect()
 87→            })
 88→            .unwrap_or_default();
 89→
 90→        if !moltis_skills::parse::validate_name(name) {
 91→            return Err(Error::message(format!(
 92→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
 93→            ))
 94→            .into());
 95→        }
 96→
 97→        let skill_dir = self.skills_dir().join(name);
 98→        if skill_dir.exists() {
 99→            return Err(Error::message(format!(
100→                "skill '{name}' already exists; use update_skill to modify it"
101→            ))
102→            .into());
103→        }
104→
105→        let content = build_skill_md(name, description, body, &allowed_tools);
106→        write_skill(&skill_dir, &content).await?;
107→
108→        Ok(json!({
109→            "created": true,
110→            "path": skill_dir.display().to_string()
111→        }))
112→    }
113→}
