214→/// Tool that deletes a personal skill from `<data_dir>/skills/`.
215→pub struct DeleteSkillTool {
216→    data_dir: PathBuf,
217→}
218→
219→impl DeleteSkillTool {
220→    pub fn new(data_dir: PathBuf) -> Self {
221→        Self { data_dir }
222→    }
223→
224→    fn skills_dir(&self) -> PathBuf {
225→        self.data_dir.join("skills")
226→    }
227→}
228→
229→#[async_trait]
230→impl AgentTool for DeleteSkillTool {
231→    fn name(&self) -> &str {
232→        "delete_skill"
233→    }
234→
235→    fn description(&self) -> &str {
236→        "Delete a personal skill. Only works for skills in <data_dir>/skills/."
237→    }
238→
239→    fn parameters_schema(&self) -> Value {
240→        json!({
241→            "type": "object",
242→            "required": ["name"],
243→            "properties": {
244→                "name": {
245→                    "type": "string",
246→                    "description": "Skill name to delete"
247→                }
248→            }
249→        })
250→    }
251→
252→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
253→        let name = params
254→            .get("name")
255→            .and_then(|v| v.as_str())
256→            .ok_or_else(|| Error::message("missing 'name'"))?;
257→
258→        if !moltis_skills::parse::validate_name(name) {
259→            return Err(Error::message(format!("invalid skill name '{name}'")).into());
260→        }
261→
262→        let skill_dir = self.skills_dir().join(name);
263→
264→        // Only allow deleting from the personal skills directory.
265→        let canonical_base = self
266→            .skills_dir()
267→            .canonicalize()
268→            .unwrap_or_else(|_| self.skills_dir().clone());
269→        let canonical_target = skill_dir
270→            .canonicalize()
271→            .unwrap_or_else(|_| skill_dir.clone());
272→        if !canonical_target.starts_with(&canonical_base) {
273→            return Err(Error::message("can only delete personal skills").into());
274→        }
275→
276→        if !skill_dir.exists() {
277→            return Err(Error::message(format!("skill '{name}' not found")).into());
278→        }
279→
280→        tokio::fs::remove_dir_all(&skill_dir).await?;
281→
282→        Ok(json!({ "deleted": true }))
283→    }
284→}
285→
286→fn build_skill_md(name: &str, description: &str, body: &str, allowed_tools: &[String]) -> String {
287→    let mut frontmatter = format!("---\nname: {name}\ndescription: {description}\n");
288→    if !allowed_tools.is_empty() {
289→        frontmatter.push_str("allowed_tools:\n");
290→        for tool in allowed_tools {
291→            frontmatter.push_str(&format!("  - {tool}\n"));
292→        }
293→    }
294→    frontmatter.push_str("---\n\n");
295→    frontmatter.push_str(body);
296→    if !body.ends_with('\n') {
297→        frontmatter.push('\n');
298→    }
299→    frontmatter
300→}
301→
302→async fn write_skill(skill_dir: &Path, content: &str) -> crate::Result<()> {
303→    tokio::fs::create_dir_all(skill_dir).await?;
304→    tokio::fs::write(skill_dir.join("SKILL.md"), content).await?;
305→    Ok(())
306→}
