18→/**
19→ * Fetch all voice providers (TTS + STT).
20→ * Resolves with the RPC response; payload has `{ tts: [], stt: [] }`.
21→ */
22→export function fetchVoiceProviders() {
23→	return sendRpc("voice.providers.all", {});
