26→/**
27→ * Toggle a voice provider on or off.
28→ * @param {string} providerId - e.g. "elevenlabs"
29→ * @param {boolean} enabled
30→ * @param {string} type - "tts" | "stt"
31→ */
32→export function toggleVoiceProvider(providerId, enabled, type) {
33→	return sendRpc("voice.provider.toggle", { provider: providerId, enabled, type });
34→}
