36→/**
37→ * Save an API key (and optional settings) for a voice provider.
38→ * @param {string} providerId
39→ * @param {string} apiKey
40→ * @param {object} [opts] - Optional TTS settings: voice, model, languageCode
41→ */
42→export function saveVoiceKey(providerId, apiKey, opts) {
43→	var payload = { provider: providerId, api_key: apiKey };
44→	if (opts?.voice) {
45→		payload.voice = opts.voice;
46→		payload.voiceId = opts.voice;
47→	}
48→	if (opts?.model) payload.model = opts.model;
49→	if (opts?.languageCode) payload.languageCode = opts.languageCode;
50→	return sendRpc("voice.config.save_key", payload);
51→}
