62→/**
63→ * Upload an audio blob for STT transcription.
64→ * @param {string} sessionKey - active session key from state
65→ * @param {string} providerId
66→ * @param {Blob} audioBlob
67→ * @returns {Promise<Response>} raw fetch Response
68→ */
69→export function transcribeAudio(sessionKey, providerId, audioBlob) {
70→	return fetch(
71→		`/api/sessions/${encodeURIComponent(sessionKey)}/upload?transcribe=true&provider=${encodeURIComponent(providerId)}`,
72→		{
73→			method: "POST",
74→			headers: { "Content-Type": audioBlob.type || "audio/webm" },
75→			body: audioBlob,
76→		},
77→	);
78→}
