80→/**
81→ * Decode a base64 (or base64url) string to a Uint8Array, tolerating
82→ * whitespace, URL-safe characters, and missing padding.
83→ */
84→export function decodeBase64Safe(input) {
85→	if (!input) return new Uint8Array();
86→	var normalized = String(input).replace(/\s+/g, "").replace(/-/g, "+").replace(/_/g, "/");
87→	while (normalized.length % 4) normalized += "=";
88→	var binary = "";
89→	try {
90→		binary = atob(normalized);
91→	} catch (_err) {
92→		throw new Error("Invalid base64 audio payload");
93→	}
94→	var bytes = new Uint8Array(binary.length);
95→	for (var i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
96→	return bytes;
97→}
