  3→const MODEL_SERVICE_NOT_CONFIGURED = "model service not configured";
  4→const MODEL_TEST_RETRY_ATTEMPTS = 40;
  5→const MODEL_TEST_RETRY_DELAY_MS = 250;
  6→
  7→function firstProbeFailure(payload) {
  8→	var results = Array.isArray(payload?.results) ? payload.results : [];
  9→	var failed = results.find((r) => r?.status === "error" || r?.status === "unsupported");
 10→	if (!failed) return null;
 11→	if (typeof failed.error === "string" && failed.error.trim()) {
 12→		return failed.error.trim();
 13→	}
 14→	return null;
 15→}
 16→
 17→/**
 18→ * Map raw error strings to user-friendly messages.
 19→ */
 20→export function humanizeProbeError(error) {
 21→	if (!error || typeof error !== "string") return error;
 22→	var lower = error.toLowerCase();
 23→
 24→	if (
 25→		lower.includes("401") ||
 26→		lower.includes("unauthorized") ||
 27→		lower.includes("invalid api key") ||
 28→		lower.includes("invalid x-api-key")
 29→	) {
 30→		return "Invalid API key. Please double-check and try again.";
 31→	}
 32→	if (lower.includes("403") || lower.includes("forbidden") || lower.includes("permission")) {
 33→		return "Your API key doesn't have access. Check your account permissions.";
 34→	}
 35→	if (lower.includes("429") || lower.includes("rate limit") || lower.includes("too many requests")) {
 36→		return "Rate limited by the provider. Wait a moment and try again.";
 37→	}
 38→	if (lower.includes("timeout") || lower.includes("timed out")) {
 39→		return "Connection timed out. Check your endpoint URL and try again.";
 40→	}
 41→	if (lower.includes("connection refused") || lower.includes("econnrefused")) {
 42→		return "Connection refused. Make sure the provider endpoint is running and reachable.";
 43→	}
 44→	if (lower.includes("dns") || lower.includes("getaddrinfo") || lower.includes("name or service not known")) {
 45→		return "Could not resolve the endpoint address. Check the URL and try again.";
 46→	}
 47→
 48→	return error;
 49→}
 50→
 51→export function isModelServiceNotConfigured(error) {
 52→	if (!error || typeof error !== "string") return false;
 53→	return error.toLowerCase().includes(MODEL_SERVICE_NOT_CONFIGURED);
 54→}
 55→
 56→/**
 57→ * Validate provider credentials without saving them.
 58→ * Returns { valid, models?, error? }.
 59→ */
 60→export async function validateProviderKey(provider, apiKey, baseUrl, model, requestId) {
 61→	var payload = { provider, apiKey };
 62→	if (baseUrl) payload.baseUrl = baseUrl;
 63→	if (model) payload.model = model;
 64→	if (requestId) payload.requestId = requestId;
 65→
 66→	var res = await sendRpc("providers.validate_key", payload);
 67→	if (!res?.ok) {
 68→		return {
 69→			valid: false,
 70→			error: humanizeProbeError(res?.error?.message || "Failed to validate credentials."),
 71→		};
 72→	}
 73→
 74→	var data = res.payload || {};
 75→	if (data.valid) {
 76→		return { valid: true, models: data.models || [] };
 77→	}
 78→	return {
 79→		valid: false,
 80→		error: humanizeProbeError(data.error || "Validation failed."),
 81→	};
 82→}
 83→
 84→/**
 85→ * Test a single model from the live registry.
 86→ * Returns { ok, error? }.
 87→ */
 88→export async function testModel(modelId) {
 89→	for (var attempt = 0; attempt < MODEL_TEST_RETRY_ATTEMPTS; attempt++) {
 90→		var res = await sendRpc("models.test", { modelId });
 91→		if (res?.ok) {
 92→			return { ok: true };
 93→		}
 94→
 95→		var message = res?.error?.message || "Model test failed.";
 96→		var lower = String(message).toLowerCase();
 97→		var shouldRetry = lower.includes(MODEL_SERVICE_NOT_CONFIGURED) && attempt < MODEL_TEST_RETRY_ATTEMPTS - 1;
 98→
 99→		if (!shouldRetry) {
100→			return {
101→				ok: false,
102→				error: humanizeProbeError(message),
103→			};
104→		}
105→
106→		await new Promise((resolve) => {
107→			window.setTimeout(resolve, MODEL_TEST_RETRY_DELAY_MS);
108→		});
109→	}
110→
111→	return {
112→		ok: false,
113→		error: humanizeProbeError("Model test failed."),
114→	};
115→}
