117→/**
118→ * Build the payload for a `providers.save_key` RPC call.
119→ */
120→export function buildSaveKeyPayload(providerName, apiKey, baseUrl, model) {
121→	var payload = { provider: providerName, apiKey };
122→	if (baseUrl) payload.baseUrl = baseUrl;
123→	if (model) payload.model = model;
124→	return payload;
125→}
126→
127→/**
128→ * Persist provider credentials via the `providers.save_key` RPC.
129→ * Returns the RPC response (check `.ok` for success).
130→ */
131→export function saveProviderKey(providerName, apiKey, baseUrl, model) {
132→	var payload = buildSaveKeyPayload(providerName, apiKey, baseUrl, model);
133→	return sendRpc("providers.save_key", payload);
134→}
