136→export async function validateProviderConnection(providerName) {
137→	var res = await sendRpc("models.detect_supported", {
138→		provider: providerName,
139→		reason: "provider_credentials_validation",
140→	});
141→
142→	if (!res?.ok) {
143→		return {
144→			ok: false,
145→			message: res?.error?.message || "Failed to validate provider credentials.",
146→		};
147→	}
148→
149→	var payload = res.payload || {};
150→	var total = payload.total || 0;
151→	var supported = payload.supported || 0;
152→	var unsupported = payload.unsupported || 0;
153→	var errors = payload.errors || 0;
154→
155→	if (supported > 0) {
156→		return {
157→			ok: true,
158→			message: null,
159→		};
160→	}
161→
162→	// No probe targets usually means no model is configured yet.
163→	if (total === 0) {
164→		return {
165→			ok: true,
166→			message: null,
167→		};
168→	}
169→
170→	var reason = firstProbeFailure(payload);
171→	if (!reason) {
172→		reason = `0/${total} models responded successfully (unsupported: ${unsupported}, errors: ${errors}).`;
173→	}
174→
175→	return {
176→		ok: false,
177→		message: `Credentials were saved, but validation failed: ${reason}`,
178→	};
179→}
