  1→//! Service trait interfaces for domain services.
  2→//!
  3→//! Each trait has a `Noop` implementation that returns empty/default responses,
  4→//! allowing the gateway to run standalone before domain crates are wired in.
  5→
  6→use {async_trait::async_trait, serde_json::Value, tracing::warn};
  7→
  8→/// Error type returned by service methods.
  9→#[derive(Debug, thiserror::Error)]
 10→pub enum ServiceError {
 11→    #[error("{message}")]
 12→    Message { message: String },
 13→    #[error("{0}")]
 14→    Serde(#[from] serde_json::Error),
 15→}
 16→
 17→impl ServiceError {
 18→    #[must_use]
 19→    pub fn message(message: impl std::fmt::Display) -> Self {
 20→        Self::Message {
 21→            message: message.to_string(),
 22→        }
 23→    }
 24→}
 25→
 26→impl From<String> for ServiceError {
 27→    fn from(value: String) -> Self {
 28→        Self::message(value)
 29→    }
 30→}
 31→
 32→impl From<&str> for ServiceError {
 33→    fn from(value: &str) -> Self {
 34→        Self::message(value)
 35→    }
 36→}
 37→
 38→impl From<ServiceError> for moltis_protocol::ErrorShape {
 39→    fn from(err: ServiceError) -> Self {
 40→        Self::new(moltis_protocol::error_codes::UNAVAILABLE, err.to_string())
 41→    }
 42→}
 43→
 44→pub type ServiceResult<T = Value> = Result<T, ServiceError>;
 45→
 46→// ── Agent ───────────────────────────────────────────────────────────────────
 47→
 48→#[async_trait]
 49→pub trait AgentService: Send + Sync {
 50→    async fn run(&self, params: Value) -> ServiceResult;
 51→    async fn run_wait(&self, params: Value) -> ServiceResult;
 52→    async fn identity_get(&self) -> ServiceResult;
 53→    async fn list(&self) -> ServiceResult;
 54→}
 55→
 56→pub struct NoopAgentService;
 57→
 58→#[async_trait]
 59→impl AgentService for NoopAgentService {
 60→    async fn run(&self, _params: Value) -> ServiceResult {
 61→        Err("agent service not configured".into())
 62→    }
 63→
 64→    async fn run_wait(&self, _params: Value) -> ServiceResult {
 65→        Err("agent service not configured".into())
 66→    }
 67→
 68→    async fn identity_get(&self) -> ServiceResult {
 69→        Ok(serde_json::json!({ "name": "moltis", "avatar": null }))
 70→    }
 71→
 72→    async fn list(&self) -> ServiceResult {
 73→        Ok(serde_json::json!([]))
 74→    }
 75→}
 76→
 77→// ── Sessions ────────────────────────────────────────────────────────────────
 78→
 79→#[async_trait]
 80→pub trait SessionService: Send + Sync {
 81→    async fn list(&self) -> ServiceResult;
 82→    async fn preview(&self, params: Value) -> ServiceResult;
 83→    async fn resolve(&self, params: Value) -> ServiceResult;
 84→    async fn patch(&self, params: Value) -> ServiceResult;
 85→    async fn voice_generate(&self, params: Value) -> ServiceResult;
 86→    async fn share_create(&self, params: Value) -> ServiceResult;
 87→    async fn share_list(&self, params: Value) -> ServiceResult;
 88→    async fn share_revoke(&self, params: Value) -> ServiceResult;
 89→    async fn reset(&self, params: Value) -> ServiceResult;
 90→    async fn delete(&self, params: Value) -> ServiceResult;
 91→    async fn compact(&self, params: Value) -> ServiceResult;
 92→    async fn search(&self, params: Value) -> ServiceResult;
 93→    async fn fork(&self, params: Value) -> ServiceResult;
 94→    async fn branches(&self, params: Value) -> ServiceResult;
 95→    async fn run_detail(&self, params: Value) -> ServiceResult;
 96→    async fn clear_all(&self) -> ServiceResult;
 97→    async fn mark_seen(&self, key: &str);
 98→}
