 25→async fn sync_webauthn_host_and_notice(state: &AppState, hostname: Option<&str>) -> Option<String> {
 26→    let hostname = hostname?;
 27→    let normalized = crate::auth_webauthn::normalize_host(hostname);
 28→    if normalized.is_empty() {
 29→        return None;
 30→    }
 31→
 32→    let registry = state.webauthn_registry.as_ref()?;
 33→    if registry.read().await.contains_host(&normalized) {
 34→        return None;
 35→    }
 36→
 37→    let scheme = if state.gateway.tls_active {
 38→        "https"
 39→    } else {
 40→        "http"
 41→    };
 42→    let origin = format!("{scheme}://{normalized}:{}", state.gateway.port);
 43→    let origin_url = match webauthn_rs::prelude::Url::parse(&origin) {
 44→        Ok(url) => url,
 45→        Err(e) => {
 46→            warn!(host = %normalized, origin = %origin, "invalid runtime WebAuthn origin: {e}");
 47→            return None;
 48→        },
 49→    };
 50→    let webauthn = match crate::auth_webauthn::WebAuthnState::new(&normalized, &origin_url, &[]) {
 51→        Ok(wa) => wa,
 52→        Err(e) => {
 53→            warn!(host = %normalized, "failed to initialize runtime WebAuthn RP: {e}");
 54→            return None;
 55→        },
 56→    };
 57→
 58→    {
 59→        let mut reg = registry.write().await;
 60→        if reg.contains_host(&normalized) {
 61→            return None;
 62→        }
 63→        reg.add(normalized.clone(), webauthn);
 64→        info!(
 65→            host = %normalized,
 66→            origins = ?reg.get_all_origins(),
 67→            "WebAuthn RP registered from tailscale runtime status"
 68→        );
 69→    }
 70→
 71→    let has_passkeys = if let Some(store) = state.gateway.credential_store.as_ref() {
 72→        store.has_passkeys().await.unwrap_or(false)
 73→    } else {
 74→        false
 75→    };
 76→
 77→    if has_passkeys {
 78→        state
 79→            .gateway
 80→            .add_passkey_host_update_pending(&normalized)
 81→            .await;
 82→        Some(format!(
 83→            "New host detected ({normalized}). Existing passkeys may not work on this host. Sign in with password, then add a new passkey in Settings > Authentication."
 84→        ))
 85→    } else {
 86→        None
 87→    }
 88→}
