109→async fn status_handler(State(state): State<AppState>) -> impl IntoResponse {
110→    debug!("tailscale status requested");
111→    let port = state.gateway.port;
112→    let manager = CliTailscaleManager::new();
113→    match manager.status().await {
114→        Ok(status) => {
115→            let passkey_warning =
116→                sync_webauthn_host_and_notice(&state, status.hostname.as_deref()).await;
117→            debug!(
118→                mode = %status.mode,
119→                hostname = ?status.hostname,
120→                tailscale_up = status.tailscale_up,
121→                "tailscale status OK"
122→            );
123→            Json(serde_json::json!({
124→                "mode": status.mode,
125→                "hostname": status.hostname,
126→                "url": status.url,
127→                "tailscale_up": status.tailscale_up,
128→                "installed": status.installed,
129→                "tailnet": status.tailnet,
130→                "version": status.version,
131→                "login_name": status.login_name,
132→                "tailscale_ip": status.tailscale_ip,
133→                "port": port,
134→                "passkey_warning": passkey_warning,
135→            }))
136→            .into_response()
137→        },
138→        Err(e) => {
139→            error!("tailscale status failed: {e}");
140→            (
141→                StatusCode::INTERNAL_SERVER_ERROR,
142→                Json(tailscale_error(TAILSCALE_STATUS_FAILED, e.to_string())),
143→            )
144→                .into_response()
145→        },
146→    }
147→}
148→
149→async fn configure_handler(
150→    State(state): State<AppState>,
151→    Json(body): Json<ConfigureRequest>,
152→) -> impl IntoResponse {
153→    info!(requested_mode = %body.mode, "tailscale configure requested");
154→
155→    let mode: TailscaleMode = match body.mode.parse() {
156→        Ok(m) => m,
157→        Err(e) => {
158→            warn!(mode = %body.mode, "invalid tailscale mode: {e}");
159→            return (
160→                StatusCode::BAD_REQUEST,
161→                Json(tailscale_error(TAILSCALE_MODE_INVALID, e.to_string())),
162→            )
163→                .into_response();
164→        },
165→    };
166→
167→    // Check auth requirement for funnel.
168→    let auth_setup_complete = state
169→        .gateway
170→        .credential_store
171→        .as_ref()
172→        .is_some_and(|cs| cs.is_setup_complete());
173→
174→    // Use the gateway's bind address for loopback validation.
175→    let bind_addr = if state.gateway.localhost_only {
176→        "127.0.0.1"
177→    } else {
178→        "0.0.0.0"
179→    };
180→
181→    if let Err(e) = validate_tailscale_config(mode, bind_addr, auth_setup_complete) {
182→        warn!(mode = %mode, "tailscale config validation failed: {e}");
183→        return (
184→            StatusCode::BAD_REQUEST,
185→            Json(tailscale_error(TAILSCALE_CONFIG_INVALID, e.to_string())),
186→        )
187→            .into_response();
188→    }
189→
190→    let manager = CliTailscaleManager::new();
191→
192→    let tls = state.gateway.tls_active;
193→    let port = state.gateway.port;
194→    info!(mode = %mode, port, tls, "applying tailscale mode");
195→    let result = match mode {
196→        TailscaleMode::Off => manager.disable().await,
197→        TailscaleMode::Serve => manager.enable_serve(port, tls).await,
198→        TailscaleMode::Funnel => manager.enable_funnel(port, tls).await,
199→    };
200→
201→    match result {
202→        Ok(()) => {
203→            info!(mode = %mode, "tailscale mode applied successfully");
204→            let status = manager.status().await.ok();
205→            let passkey_warning = if let Some(ref s) = status {
206→                sync_webauthn_host_and_notice(&state, s.hostname.as_deref()).await
207→            } else {
208→                None
209→            };
210→            if let Some(ref s) = status {
211→                info!(
212→                    active_mode = %s.mode,
213→                    hostname = ?s.hostname,
214→                    url = ?s.url,
215→                    "tailscale status after configure"
216→                );
217→            }
218→            Json(serde_json::json!({
219→                "ok": true,
220→                "mode": mode,
221→                "status": status.map(|s| serde_json::json!({
222→                    "mode": s.mode,
223→                    "hostname": s.hostname,
224→                    "url": s.url,
225→                    "tailscale_up": s.tailscale_up,
226→                    "installed": s.installed,
227→                    "tailnet": s.tailnet,
228→                    "version": s.version,
229→                    "login_name": s.login_name,
230→                })),
231→                "passkey_warning": passkey_warning,
232→            }))
233→            .into_response()
234→        },
235→        Err(e) => {
236→            error!(mode = %mode, "tailscale configure failed: {e}");
237→            (
238→                StatusCode::INTERNAL_SERVER_ERROR,
239→                Json(tailscale_error(TAILSCALE_CONFIGURE_FAILED, e.to_string())),
240→            )
241→                .into_response()
242→        },
243→    }
244→}
