 16→/// Errors from agent persona operations.
 17→#[derive(Debug, thiserror::Error)]
 18→pub enum AgentError {
 19→    #[error("{0}")]
 20→    NotFound(String),
 21→    #[error("{0}")]
 22→    InvalidRequest(String),
 23→    #[error(transparent)]
 24→    Db(#[from] sqlx::Error),
 25→    #[error(transparent)]
 26→    Io(#[from] std::io::Error),
 27→    #[error(transparent)]
 28→    Config(#[from] moltis_config::Error),
 29→}
 30→
 31→impl From<AgentError> for moltis_protocol::ErrorShape {
 32→    fn from(err: AgentError) -> Self {
 33→        use moltis_protocol::error_codes;
 34→        match &err {
 35→            AgentError::NotFound(_) | AgentError::InvalidRequest(_) => {
 36→                Self::new(error_codes::INVALID_REQUEST, err.to_string())
 37→            },
 38→            AgentError::Db(_) | AgentError::Io(_) | AgentError::Config(_) => {
 39→                Self::new(error_codes::UNAVAILABLE, err.to_string())
 40→            },
 41→        }
 42→    }
 43→}
 44→
 45→type Result<T> = std::result::Result<T, AgentError>;
