124→/// Validate an agent ID: lowercase alphanumeric + hyphens, 1-50 chars, not "main".
125→pub fn validate_agent_id(id: &str) -> Result<()> {
126→    if id == "main" {
127→        return Err(AgentError::InvalidRequest(
128→            "cannot use reserved id 'main'".into(),
129→        ));
130→    }
131→    if id.is_empty() || id.len() > 50 {
132→        return Err(AgentError::InvalidRequest(
133→            "id must be 1-50 characters".into(),
134→        ));
135→    }
136→    if !id
137→        .chars()
138→        .all(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || c == '-')
139→    {
140→        return Err(AgentError::InvalidRequest(
141→            "id must contain only lowercase letters, digits, and hyphens".into(),
142→        ));
143→    }
144→    if id.starts_with('-') || id.ends_with('-') {
145→        return Err(AgentError::InvalidRequest(
146→            "id must not start or end with a hyphen".into(),
147→        ));
148→    }
149→    Ok(())
150→}
