152→/// SQLite-backed agent persona store.
153→pub struct AgentPersonaStore {
154→    pool: sqlx::SqlitePool,
155→}
156→
157→impl AgentPersonaStore {
158→    pub fn new(pool: sqlx::SqlitePool) -> Self {
159→        Self { pool }
160→    }
161→
162→    /// Return the current default agent ID.
163→    ///
164→    /// If no explicit default row is set, this falls back to `"main"`.
165→    pub async fn default_id(&self) -> Result<String> {
166→        let row = sqlx::query_scalar::<_, String>(
167→            "SELECT id FROM agents WHERE is_default = 1 ORDER BY updated_at DESC LIMIT 1",
168→        )
169→        .fetch_optional(&self.pool)
170→        .await?;
171→        Ok(row.unwrap_or_else(|| "main".to_string()))
172→    }
173→
174→    /// Set the default agent ID. `"main"` is always valid.
175→    pub async fn set_default(&self, id: &str) -> Result<String> {
176→        if id != "main" && self.get(id).await?.is_none() {
177→            return Err(AgentError::NotFound(format!("agent '{id}' not found")));
178→        }
179→
180→        let mut tx = self.pool.begin().await?;
181→        sqlx::query("UPDATE agents SET is_default = 0")
182→            .execute(&mut *tx)
183→            .await?;
184→
185→        if id != "main" {
186→            let now = now_ms();
187→            let updated =
188→                sqlx::query("UPDATE agents SET is_default = 1, updated_at = ? WHERE id = ?")
189→                    .bind(now)
190→                    .bind(id)
191→                    .execute(&mut *tx)
192→                    .await?;
193→            if updated.rows_affected() == 0 {
194→                return Err(AgentError::NotFound(format!("agent '{id}' not found")));
195→            }
196→        }
197→
198→        tx.commit().await?;
199→        Ok(id.to_string())
200→    }
201→
202→    /// Ensure the default main workspace exists and is seeded from the root
203→    /// workspace when files are present there.
204→    pub fn ensure_main_workspace_seeded(&self) -> Result<PathBuf> {
205→        let main_workspace = moltis_config::agent_workspace_dir("main");
206→        std::fs::create_dir_all(&main_workspace)?;
207→
208→        for file_name in &[
209→            "IDENTITY.md",
210→            "SOUL.md",
211→            "MEMORY.md",
212→            "AGENTS.md",
213→            "TOOLS.md",
214→        ] {
215→            let src = moltis_config::data_dir().join(file_name);
216→            let dst = main_workspace.join(file_name);
217→            if src.exists() && !dst.exists() {
218→                let _ = std::fs::copy(&src, &dst)?;
219→            }
220→        }
221→
222→        let src_memory_dir = moltis_config::data_dir().join("memory");
223→        let dst_memory_dir = main_workspace.join("memory");
224→        if src_memory_dir.exists() && src_memory_dir.is_dir() && !dst_memory_dir.exists() {
225→            copy_dir_recursive(&src_memory_dir, &dst_memory_dir)?;
226→        }
227→
228→        Ok(main_workspace)
229→    }
230→
231→    /// List all agents: synthesize "main" from config, then append DB rows.
232→    pub async fn list(&self) -> Result<Vec<AgentPersona>> {
233→        let _ = self.ensure_main_workspace_seeded();
234→        let default_id = self.default_id().await?;
235→        let main = synthesize_main_agent(default_id == "main");
236→        let db_agents: Vec<AgentPersona> =
237→            sqlx::query_as::<_, AgentRow>("SELECT * FROM agents ORDER BY created_at ASC")
238→                .fetch_all(&self.pool)
239→                .await?
240→                .into_iter()
241→                .map(Into::into)
242→                .collect();
243→
244→        let mut result = vec![main];
