262→    /// Create a new agent persona and its workspace directory.
263→    pub async fn create(&self, params: CreateAgentParams) -> Result<AgentPersona> {
264→        validate_agent_id(&params.id)?;
265→
266→        let now = now_ms();
267→        sqlx::query(
268→            r#"INSERT INTO agents (id, name, is_default, emoji, theme, description, created_at, updated_at)
269→               VALUES (?, ?, 0, ?, ?, ?, ?, ?)"#,
270→        )
271→        .bind(&params.id)
272→        .bind(&params.name)
273→        .bind(&params.emoji)
274→        .bind(&params.theme)
275→        .bind(&params.description)
276→        .bind(now)
277→        .bind(now)
278→        .execute(&self.pool)
279→        .await?;
280→
281→        self.ensure_workspace(&params.id)?;
282→
283→        // Write initial IDENTITY.md and SOUL.md if values provided.
284→        let identity = moltis_config::schema::AgentIdentity {
285→            name: Some(params.name.clone()),
286→            emoji: params.emoji.clone(),
287→            theme: params.theme.clone(),
