303→    /// Update an existing agent persona.
304→    pub async fn update(&self, id: &str, params: UpdateAgentParams) -> Result<AgentPersona> {
305→        if id == "main" {
306→            return Err(AgentError::InvalidRequest(
307→                "cannot modify 'main' agent through this API; use identity settings".into(),
308→            ));
309→        }
310→
311→        let existing = self
312→            .get(id)
313→            .await?
314→            .ok_or_else(|| AgentError::NotFound(format!("agent '{id}' not found")))?;
315→
316→        let name = params.name.unwrap_or(existing.name);
317→        let emoji = params.emoji.or(existing.emoji);
318→        let theme = params.theme.or(existing.theme);
319→        let description = params.description.or(existing.description);
320→        let now = now_ms();
321→
322→        sqlx::query(
323→            "UPDATE agents SET name = ?, emoji = ?, theme = ?, description = ?, updated_at = ? WHERE id = ?",
324→        )
325→        .bind(&name)
326→        .bind(&emoji)
327→        .bind(&theme)
328→        .bind(&description)
329→        .bind(now)
330→        .bind(id)
331→        .execute(&self.pool)
332→        .await?;
333→
334→        // Update workspace IDENTITY.md.
335→        let identity = moltis_config::schema::AgentIdentity {
336→            name: Some(name.clone()),
337→            emoji: emoji.clone(),
338→            theme: theme.clone(),
339→        };
340→        moltis_config::save_identity_for_agent(id, &identity)?;
341→
342→        Ok(AgentPersona {
343→            id: id.to_string(),
344→            name,
345→            is_default: existing.is_default,
346→            emoji,
347→            theme,
348→            description,
349→            created_at: existing.created_at,
350→            updated_at: now,
351→        })
352→    }
353→
354→    /// Delete an agent persona. Cannot delete "main".
355→    pub async fn delete(&self, id: &str) -> Result<()> {
356→        if id == "main" {
357→            return Err(AgentError::InvalidRequest(
358→                "cannot delete the main agent".into(),
359→            ));
360→        }
361→        if self.default_id().await? == id {
362→            return Err(AgentError::InvalidRequest(
363→                "cannot delete the default agent".into(),
364→            ));
365→        }
366→
367→        let result = sqlx::query("DELETE FROM agents WHERE id = ?")
368→            .bind(id)
369→            .execute(&self.pool)
370→            .await?;
371→
372→        if result.rows_affected() == 0 {
373→            return Err(AgentError::NotFound(format!("agent '{id}' not found")));
374→        }
375→
376→        // Archive the workspace directory by renaming it.
377→        let workspace = moltis_config::agent_workspace_dir(id);
378→        if workspace.exists() {
379→            let archived = workspace.with_file_name(format!("{id}.archived"));
380→            if let Err(e) = std::fs::rename(&workspace, &archived) {
381→                tracing::warn!(
382→                    agent_id = id,
383→                    error = %e,
384→                    "failed to archive agent workspace, removing instead"
385→                );
386→                let _ = std::fs::remove_dir_all(&workspace);
387→            }
388→        }
389→
390→        Ok(())
391→    }
392→
393→    /// Create the workspace directory for an agent.
394→    pub fn ensure_workspace(&self, agent_id: &str) -> Result<PathBuf> {
395→        let dir = moltis_config::agent_workspace_dir(agent_id);
396→        std::fs::create_dir_all(&dir)?;
397→        Ok(dir)
398→    }
399→}
