402→fn synthesize_main_agent(is_default: bool) -> AgentPersona {
403→    let identity = moltis_config::load_identity_for_agent("main");
404→    AgentPersona {
405→        id: "main".to_string(),
406→        name: identity
407→            .as_ref()
408→            .and_then(|i| i.name.clone())
409→            .unwrap_or_else(|| "moltis".to_string()),
410→        is_default,
411→        emoji: identity.as_ref().and_then(|i| i.emoji.clone()),
412→        theme: identity.as_ref().and_then(|i| i.theme.clone()),
413→        description: Some("Default agent".to_string()),
