419→fn copy_dir_recursive(src: &Path, dst: &Path) -> Result<()> {
420→    std::fs::create_dir_all(dst)?;
421→    for entry in std::fs::read_dir(src)? {
422→        let entry = entry?;
423→        let src_path = entry.path();
424→        let dst_path = dst.join(entry.file_name());
425→        let file_type = entry.file_type()?;
426→        if file_type.is_dir() {
427→            copy_dir_recursive(&src_path, &dst_path)?;
428→        } else if file_type.is_file() {
429→            let _ = std::fs::copy(src_path, dst_path)?;
430→        }
431→    }
432→    Ok(())
433→}
