 1→//! CLI subcommands for Tailscale Serve/Funnel management.
 2→
 3→use {anyhow::Result, clap::Subcommand};
 4→
 5→use moltis_gateway::tailscale::{
 6→    CliTailscaleManager, TailscaleManager, TailscaleMode, validate_tailscale_config,
 7→};
 8→
 9→#[derive(Subcommand)]
10→pub enum TailscaleAction {
11→    /// Show current tailscale serve/funnel status.
12→    Status,
13→    /// Enable tailscale serve (tailnet-only HTTPS).
14→    Serve {
15→        /// Port to proxy to (defaults to 18789).
16→        #[arg(long, default_value_t = 18789)]
17→        port: u16,
18→    },
19→    /// Enable tailscale funnel (public HTTPS).
20→    Funnel {
21→        /// Port to proxy to (defaults to 18789).
22→        #[arg(long, default_value_t = 18789)]
23→        port: u16,
24→    },
25→    /// Disable tailscale serve/funnel.
26→    Disable,
27→}
28→
29→pub async fn handle_tailscale(action: TailscaleAction) -> Result<()> {
30→    let manager = CliTailscaleManager::new();
31→
32→    match action {
33→        TailscaleAction::Status => {
34→            let status = manager.status().await?;
35→            println!("Mode:         {}", status.mode);
36→            println!("Tailscale up: {}", status.tailscale_up);
37→            if let Some(ref hostname) = status.hostname {
38→                println!("Hostname:     {hostname}");
39→            }
40→            if let Some(ref url) = status.url {
41→                println!("URL:          {url}");
42→            }
43→        },
44→        TailscaleAction::Serve { port } => {
45→            let config = moltis_config::discover_and_load();
46→            let tls = config.tls.enabled;
47→            validate_tailscale_config(TailscaleMode::Serve, "127.0.0.1", false)?;
48→            manager.enable_serve(port, tls).await?;
49→            println!("Tailscale serve enabled on port {port}");
50→            if let Ok(Some(hostname)) = manager.hostname().await {
51→                println!("URL: https://{hostname}");
52→            }
53→        },
54→        TailscaleAction::Funnel { port } => {
55→            let config = moltis_config::discover_and_load();
56→            let tls = config.tls.enabled;
57→            let has_password = !config.auth.disabled;
58→            validate_tailscale_config(TailscaleMode::Funnel, "127.0.0.1", has_password)?;
59→            manager.enable_funnel(port, tls).await?;
60→            println!("Tailscale funnel enabled on port {port}");
61→            if let Ok(Some(hostname)) = manager.hostname().await {
62→                println!("URL: https://{hostname}");
63→            }
64→        },
65→        TailscaleAction::Disable => {
66→            manager.disable().await?;
67→            println!("Tailscale serve/funnel disabled");
68→        },
69→    }
70→
71→    Ok(())
72→}
