116→function base64ToBuffer(b64) {
117→	var str = b64.replace(/-/g, "+").replace(/_/g, "/");
118→	while (str.length % 4) str += "=";
119→	var bin = atob(str);
120→	var buf = new Uint8Array(bin.length);
121→	for (var i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
122→	return buf.buffer;
123→}
124→
125→function bufferToBase64(buf) {
126→	var bytes = new Uint8Array(buf);
127→	var str = "";
128→	for (var b of bytes) str += String.fromCharCode(b);
129→	return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
130→}
