 28→async function parseLoginFailure(response) {
 29→	if (response.status === 429) {
 30→		var retryAfter = 0;
 31→		try {
 32→			var data = await response.json();
 33→			if (data && Number.isFinite(data.retry_after_seconds)) {
 34→				retryAfter = Math.max(1, Math.ceil(data.retry_after_seconds));
 35→			}
 36→		} catch {
 37→			// Ignore JSON parse errors and fall back to Retry-After header.
 38→		}
 39→		if (retryAfter <= 0) {
 40→			var retryAfterHeader = Number.parseInt(response.headers.get("Retry-After") || "0", 10);
 41→			if (Number.isFinite(retryAfterHeader) && retryAfterHeader > 0) {
 42→				retryAfter = retryAfterHeader;
 43→			}
 44→		}
 45→		return { type: "retry", retryAfter: Math.max(1, retryAfter) };
 46→	}
 47→
 48→	if (response.status === 401) {
 49→		return { type: "invalid_password" };
 50→	}
 51→
 52→	var bodyText = await response.text();
 53→	return { type: "error", message: bodyText || t("login:loginFailed") };
 54→}
