249→
250→	return renderLoginCard({
251→		title,
252→		showPassword,
253→		showPasskeys,
254→		showDivider,
255→		password,
256→		setPassword,
257→		onPasswordLogin,
258→		onPasskeyLogin,
259→		loading,
260→		retrySecondsLeft,
261→		error,
262→	});
263→}
