267→function base64ToBuffer(b64) {
268→	var str = b64.replace(/-/g, "+").replace(/_/g, "/");
269→	while (str.length % 4) str += "=";
270→	var bin = atob(str);
271→	var buf = new Uint8Array(bin.length);
272→	for (var i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
273→	return buf.buffer;
274→}
275→
276→function bufferToBase64(buf) {
277→	var bytes = new Uint8Array(buf);
278→	var str = "";
279→	for (var b of bytes) str += String.fromCharCode(b);
280→	return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
281→}
