 65→async fn resolve_session_agent_id_for_ctx(ctx: &MethodContext) -> String {
 66→    let default_id = default_agent_id_for_ctx(ctx).await;
 67→    let Some(session_key) = active_session_key_for_ctx(ctx).await else {
 68→        return default_id;
 69→    };
 70→    let Some(ref metadata) = ctx.state.services.session_metadata else {
 71→        return default_id;
 72→    };
 73→    let Some(entry) = metadata.get(&session_key).await else {
 74→        return default_id;
 75→    };
 76→    let Some(agent_id) = entry
 77→        .agent_id
 78→        .as_deref()
 79→        .map(str::trim)
 80→        .filter(|value| !value.is_empty())
 81→    else {
 82→        return default_id;
 83→    };
 84→    if agent_exists_for_ctx(ctx, agent_id).await {
 85→        return agent_id.to_string();
 86→    }
 87→    warn!(
 88→        session = %session_key,
 89→        agent_id,
 90→        fallback = %default_id,
 91→        "session references unknown agent, falling back to default"
 92→    );
 93→    let _ = metadata.set_agent_id(&session_key, Some(&default_id)).await;
 94→    default_id
