1201→	async function onStartConfigure(name) {
1202→		closeAll();
1203→		var p = providers.find((pr) => pr.name === name);
1204→		if (!p) return;
1205→		if (p.authType === "api-key") {
1206→			setEndpoint(p.baseUrl || "");
1207→			setModel(p.model || "");
1208→			if (await openModelSelectForConfiguredApiProvider(p)) return;
1209→			setConfiguring(name);
1210→			setPhase("form");
1211→			return;
1212→		} else if (p.authType === "oauth") {
1213→			startOAuth(p);
1214→		} else if (p.authType === "local") {
1215→			startLocal(p);
