1221→	function onSaveKey(e) {
1222→		e.preventDefault();
1223→		var p = providers.find((pr) => pr.name === configuring);
1224→		if (!p) return;
1225→		if (!(apiKey.trim() || p.keyOptional)) {
1226→			setError("API key is required.");
1227→			return;
1228→		}
1229→		if (BYOM_PROVIDERS.includes(p.name) && !model.trim()) {
1230→			setError("Model ID is required.");
1231→			return;
1232→		}
1233→		setError(null);
1234→		setPhase("validating");
1235→
1236→		var keyVal = apiKey.trim() || p.name;
1237→		var endpointVal = endpoint.trim() || null;
1238→		var modelVal = model.trim() || null;
1239→
1240→		validateProviderKey(p.name, keyVal, endpointVal, modelVal)
1241→			.then(async (result) => {
1242→				if (!result.valid) {
1243→					// Validation failed — stay on the form.
1244→					setPhase("form");
1245→					setError(result.error || "Validation failed. Please check your credentials.");
1246→					return;
1247→				}
1248→
1249→				// BYOM providers: we already tested the specific model during validation,
1250→				// so save immediately without showing the model selector.
1251→				if (BYOM_PROVIDERS.includes(p.name)) {
1252→					return saveAndFinishByom(p.name, keyVal, endpointVal, modelVal);
1253→				}
1254→
1255→				// Persist credentials before opening model selection so probes
1256→				// and follow-up actions use an initialized provider registry.
1257→				var saveRes = await saveProviderKey(p.name, keyVal, endpointVal, modelVal);
1258→				if (!saveRes?.ok) {
1259→					setPhase("form");
1260→					setError(saveRes?.error?.message || "Failed to save credentials.");
1261→					return;
1262→				}
1263→
1264→				// Regular providers: show the model selector.
1265→				setProviderModels(result.models || []);
1266→				setPhase("selectModel");
1267→			})
1268→			.catch((err) => {
1269→				setPhase("form");
1270→				setError(err?.message || "Validation failed.");
1271→			});
1272→	}
