1274→	function probeModelAsync(modelId) {
1275→		setProbeResults((prev) => {
1276→			var next = new Map(prev);
1277→			next.set(modelId, "probing");
1278→			return next;
1279→		});
1280→		testModel(modelId).then((result) => {
1281→			setProbeResults((prev) => {
1282→				var next = new Map(prev);
1283→				if (isModelServiceNotConfigured(result.error || "")) {
1284→					next.delete(modelId);
1285→				} else {
1286→					next.set(modelId, result.ok ? "ok" : { error: humanizeProbeError(result.error || "Unsupported") });
1287→				}
1288→				return next;
1289→			});
1290→		});
1291→	}
