1306→	function resolveCredentials(providerName, modelIds) {
1307→		var p = providers.find((pr) => pr.name === providerName);
1308→		if (!p) return null;
1309→		var keyVal = apiKey.trim() || p.name;
1310→		var endpointVal = endpoint.trim() || null;
1311→		var modelVal = model.trim() || null;
1312→		var effectiveModelVal = p.keyOptional && modelIds.length > 0 ? modelIds[0] : modelVal;
1313→		return { keyVal, endpointVal, modelVal: effectiveModelVal };
1314→	}
