1316→	async function saveProviderKeyIfNeeded(providerName, modelIds) {
1317→		if (modelSelectProvider) return true;
1318→		var creds = resolveCredentials(providerName, modelIds);
1319→		if (!creds) return false;
1320→		var res = await saveProviderKey(providerName, creds.keyVal, creds.endpointVal, creds.modelVal);
1321→		if (!res?.ok) {
1322→			setPhase("form");
1323→			setError(res?.error?.message || "Failed to save credentials.");
1324→			return false;
1325→		}
1326→		return true;
1327→	}
