1329→	async function onSaveSelectedModels() {
1330→		var providerName = modelSelectProvider || configuring;
1331→		if (!providerName) return false;
1332→		var modelIds = Array.from(selectedModels);
1333→
1334→		setSavingModels(true);
1335→		setError(null);
1336→
1337→		try {
1338→			if (!(await saveProviderKeyIfNeeded(providerName, modelIds))) {
1339→				setSavingModels(false);
1340→				return false;
1341→			}
1342→			var res = await sendRpc("providers.save_models", { provider: providerName, models: modelIds });
1343→			if (!res?.ok) {
1344→				setSavingModels(false);
1345→				setError(res?.error?.message || "Failed to save model preferences.");
1346→				return false;
1347→			}
1348→			if (modelIds.length > 0) {
1349→				localStorage.setItem("moltis-model", modelIds[0]);
1350→			}
1351→			setValidationResults((prev) => ({ ...prev, [providerName]: { ok: true, message: null } }));
1352→			closeAll();
1353→			refreshProviders();
1354→			return true;
1355→		} catch (err) {
1356→			setSavingModels(false);
1357→			setError(err?.message || "Failed to save credentials.");
1358→			return false;
1359→		}
1360→	}
