1362→	async function onContinue() {
1363→		var hasPendingModelSelection =
1364→			phase === "selectModel" && (configuring || modelSelectProvider) && selectedModels.size > 0;
1365→		if (hasPendingModelSelection) {
1366→			var saved = await onSaveSelectedModels();
1367→			if (!saved) return;
1368→		}
1369→		onNext();
