1372→	// BYOM-only save path (no model selector shown for these providers).
1373→	function saveAndFinishByom(providerName, keyVal, endpointVal, modelVal) {
1374→		saveProviderKey(providerName, keyVal, endpointVal, modelVal)
1375→			.then(async (res) => {
1376→				if (!res?.ok) {
1377→					setPhase("form");
1378→					setError(res?.error?.message || "Failed to save credentials.");
1379→					return;
1380→				}
1381→
1382→				// Test the specific model from the live registry.
1383→				if (modelVal) {
1384→					var testResult = await testModel(modelVal);
1385→					var modelServiceUnavailable = !testResult.ok && isModelServiceNotConfigured(testResult.error || "");
1386→					if (!(testResult.ok || modelServiceUnavailable)) {
1387→						setPhase("form");
1388→						setError(testResult.error || "Model test failed. Check your model ID.");
1389→						return;
1390→					}
1391→					await sendRpc("providers.save_models", { provider: providerName, models: [modelVal] });
1392→					localStorage.setItem("moltis-model", modelVal);
1393→				}
1394→
1395→				setValidationResults((prev) => ({ ...prev, [providerName]: { ok: true, message: null } }));
1396→				setConfiguring(null);
1397→				setPhase("form");
1398→				setProviderModels([]);
1399→				setSelectedModels(new Set());
1400→				setProbeResults(new Map());
1401→				setModelSearch("");
1402→				setApiKey("");
1403→				setEndpoint("");
1404→				setModel("");
1405→				setError(null);
1406→				refreshProviders();
1407→			})
1408→			.catch((err) => {
1409→				setPhase("form");
1410→				setError(err?.message || "Failed to save credentials.");
1411→			});
1412→	}
