1414→	// ── OAuth flow ───────────────────────────────────────────
1415→
1416→	function startOAuth(p) {
1417→		setOauthProvider(p.name);
1418→		setOauthInfo({ status: "starting" });
1419→		setOauthCallbackInput("");
1420→		setOauthSubmitting(false);
1421→		startProviderOAuth(p.name).then((result) => {
1422→			if (result.status === "already") {
1423→				onOAuthAuthenticated(p.name);
1424→			} else if (result.status === "browser") {
1425→				window.open(result.authUrl, "_blank");
1426→				setOauthInfo({ status: "waiting" });
1427→				pollOAuth(p);
1428→			} else if (result.status === "device") {
1429→				setOauthInfo({
1430→					status: "device",
1431→					uri: result.verificationUrl,
1432→					code: result.userCode,
1433→				});
1434→				pollOAuth(p);
1435→			} else {
1436→				setError(result.error || "Failed to start OAuth");
1437→				setOauthProvider(null);
1438→				setOauthInfo(null);
1439→				setOauthCallbackInput("");
1440→				setOauthSubmitting(false);
1441→			}
1442→		});
1443→	}
1444→
1445→	async function onOAuthAuthenticated(providerName) {
1446→		var provModels = await loadModelsForProvider(providerName);
1447→
1448→		setOauthProvider(null);
1449→		setOauthInfo(null);
1450→		setOauthCallbackInput("");
1451→		setOauthSubmitting(false);
1452→
1453→		if (provModels.length > 0) {
1454→			setModelSelectProvider(providerName);
1455→			setConfiguring(providerName);
1456→			setProviderModels(provModels);
1457→			setSelectedModels(new Set());
1458→			setPhase("selectModel");
1459→		} else {
1460→			sendRpc("models.detect_supported", {
1461→				background: true,
1462→				reason: "provider_connected",
1463→				provider: providerName,
1464→			});
1465→			setValidationResults((prev) => ({ ...prev, [providerName]: { ok: true, message: null } }));
1466→		}
1467→		refreshProviders();
1468→	}
1469→
1470→	function pollOAuth(p) {
1471→		var attempts = 0;
1472→		if (oauthTimerRef.current) clearInterval(oauthTimerRef.current);
1473→		oauthTimerRef.current = setInterval(() => {
1474→			attempts++;
1475→			if (attempts > 60) {
1476→				clearInterval(oauthTimerRef.current);
1477→				oauthTimerRef.current = null;
1478→				setError("OAuth timed out. Please try again.");
1479→				setOauthProvider(null);
1480→				setOauthInfo(null);
1481→				setOauthCallbackInput("");
1482→				setOauthSubmitting(false);
1483→				return;
1484→			}
1485→			sendRpc("providers.oauth.status", { provider: p.name }).then((res) => {
1486→				if (res?.ok && res.payload?.authenticated) {
1487→					clearInterval(oauthTimerRef.current);
1488→					oauthTimerRef.current = null;
1489→					onOAuthAuthenticated(p.name);
1490→				}
1491→			});
1492→		}, 2000);
1493→	}
1494→
1495→	function cancelOAuth() {
1496→		if (oauthTimerRef.current) {
1497→			clearInterval(oauthTimerRef.current);
1498→			oauthTimerRef.current = null;
1499→		}

