 57→/// Extract preview text from a single message JSON value.
 58→fn extract_preview_from_value(msg: &Value) -> Option<String> {
 59→    fn message_text(msg: &Value) -> Option<String> {
 60→        let text = if let Some(s) = msg.get("content").and_then(|v| v.as_str()) {
 61→            s.to_string()
 62→        } else if let Some(blocks) = msg.get("content").and_then(|v| v.as_array()) {
 63→            blocks
 64→                .iter()
 65→                .filter_map(|b| {
 66→                    if b.get("type").and_then(|v| v.as_str()) == Some("text") {
 67→                        b.get("text").and_then(|v| v.as_str())
 68→                    } else {
 69→                        None
 70→                    }
 71→                })
 72→                .collect::<Vec<_>>()
 73→                .join(" ")
 74→        } else {
 75→            return None;
 76→        };
 77→        let trimmed = text.trim();
 78→        if trimmed.is_empty() {
 79→            None
 80→        } else {
 81→            Some(trimmed.to_string())
 82→        }
 83→    }
 84→    fn truncate_preview(s: &str, max: usize) -> String {
 85→        if s.len() <= max {
 86→            s.to_string()
 87→        } else {
 88→            format!("{}…", &s[..s.floor_char_boundary(max)])
 89→        }
 90→    }
 91→    message_text(msg).map(|t| truncate_preview(&t, 200))
 92→}
