1024→    let skill_name = params
1025→        .get("skill")
1026→        .and_then(|v| v.as_str())
1027→        .ok_or_else(|| "missing 'skill' parameter".to_string())?;
1028→
1029→    let manifest_path =
1030→        moltis_skills::manifest::ManifestStore::default_path().map_err(ServiceError::message)?;
1031→    let store = moltis_skills::manifest::ManifestStore::new(manifest_path);
1032→    let mut manifest = store.load().map_err(ServiceError::message)?;
1033→
1034→    let install_dir =
1035→        moltis_skills::install::default_install_dir().map_err(ServiceError::message)?;
1036→    let (drift_changed, drifted_sources) = detect_and_mark_repo_drift(&mut manifest, &install_dir);
1037→    if drift_changed {
1038→        store.save(&manifest).map_err(ServiceError::message)?;
1039→    }
1040→
1041→    if enabled {
1042→        if drifted_sources.contains(source) {
1043→            return Err(format!(
1044→                "skill '{skill_name}' source changed since it was last trusted. Review and run skills.skill.trust before enabling"
1045→            )
