1049→        let trusted = manifest
1050→            .find_repo(source)
1051→            .and_then(|r| r.skills.iter().find(|s| s.name == skill_name))
1052→            .map(|s| s.trusted)
1053→            .ok_or_else(|| format!("skill '{skill_name}' not found in repo '{source}'"))?;
1054→        if !trusted {
1055→            return Err(format!(
1056→                "skill '{skill_name}' is not trusted. Review it and run skills.skill.trust before enabling"
1057→            )
1058→            .into());
1059→        }
1060→    }
1061→
1062→    if !manifest.set_skill_enabled(source, skill_name, enabled) {
1063→        return Err(format!("skill '{skill_name}' not found in repo '{source}'").into());
1064→    }
