1551→    fn priority_rank(order: &HashMap<String, usize>, model: &moltis_providers::ModelInfo) -> usize {
1552→        let full = normalize_model_key(&model.id);
1553→        if let Some(rank) = order.get(&full) {
1554→            return *rank;
1555→        }
1556→        let raw = normalize_model_key(raw_model_id(&model.id));
1557→        if let Some(rank) = order.get(&raw) {
1558→            return *rank;
1559→        }
1560→        let display = normalize_model_key(&model.display_name);
1561→        if let Some(rank) = order.get(&display) {
1562→            return *rank;
1563→        }
1564→        usize::MAX
1565→    }
