1567→    fn prioritize_models<'a>(
1568→        order: &HashMap<String, usize>,
1569→        models: impl Iterator<Item = &'a moltis_providers::ModelInfo>,
1570→    ) -> Vec<&'a moltis_providers::ModelInfo> {
1571→        let mut ordered: Vec<(usize, &'a moltis_providers::ModelInfo)> =
1572→            models.enumerate().collect();
1573→        ordered.sort_by_key(|(idx, model)| {
1574→            (
1575→                Self::priority_rank(order, model),
1576→                subscription_provider_rank(&model.provider),
1577→                *idx,
1578→            )
1579→        });
1580→        ordered.into_iter().map(|(_, model)| model).collect()
1581→    }
