  8→
  9→/// Gateway-side onboarding service backed by `moltis_onboarding::service::LiveOnboardingService`.
 10→pub struct GatewayOnboardingService {
 11→    inner: moltis_onboarding::service::LiveOnboardingService,
 12→    session_metadata: Arc<moltis_sessions::metadata::SqliteSessionMetadata>,
 13→    agent_persona_store: Arc<crate::agent_persona::AgentPersonaStore>,
 14→    gateway_state: Arc<tokio::sync::OnceCell<Arc<crate::state::GatewayState>>>,
 15→}
 16→
 17→impl GatewayOnboardingService {
 18→    pub fn new(
 19→        inner: moltis_onboarding::service::LiveOnboardingService,
 20→        session_metadata: Arc<moltis_sessions::metadata::SqliteSessionMetadata>,
 21→        agent_persona_store: Arc<crate::agent_persona::AgentPersonaStore>,
 22→        gateway_state: Arc<tokio::sync::OnceCell<Arc<crate::state::GatewayState>>>,
 23→    ) -> Self {
 24→        Self {
 25→            inner,
 26→            session_metadata,
 27→            agent_persona_store,
 28→            gateway_state,
 29→        }
 30→    }
 31→
 32→    /// Create imported agents as Moltis agent personas.
 33→    ///
 34→    /// Skips agents that already exist or are the default ("main") agent.
 35→    #[cfg(feature = "openclaw-import")]
 36→    async fn create_imported_agents(
 37→        &self,
 38→        agents: &moltis_openclaw_import::agents::ImportedAgents,
 39→    ) -> Result<(), String> {
 40→        for agent in &agents.agents {
 41→            if agent.is_default {
 42→                continue;
 43→            }
 44→
 45→            // Skip if already exists
 46→            match self.agent_persona_store.get(&agent.moltis_id).await {
 47→                Ok(Some(_)) => {
 48→                    tracing::debug!(
 49→                        id = %agent.moltis_id,
 50→                        "openclaw import: agent already exists, skipping"
 51→                    );
 52→                    continue;
 53→                },
 54→                Err(e) => {
 55→                    tracing::warn!(
 56→                        id = %agent.moltis_id,
 57→                        error = %e,
 58→                        "openclaw import: failed to check agent existence"
 59→                    );
 60→                    continue;
 61→                },
 62→                Ok(None) => {},
 63→            }
 64→
 65→            let name = agent
 66→                .name
 67→                .clone()
 68→                .unwrap_or_else(|| agent.moltis_id.clone());
 69→
 70→            let params = crate::agent_persona::CreateAgentParams {
 71→                id: agent.moltis_id.clone(),
 72→                name,
 73→                emoji: None,
 74→                theme: agent.theme.clone(),
 75→                description: None,
 76→            };
 77→
 78→            match self.agent_persona_store.create(params).await {
 79→                Ok(_) => {
 80→                    tracing::info!(
 81→                        id = %agent.moltis_id,
 82→                        "openclaw import: created agent persona"
 83→                    );
 84→                },
 85→                Err(e) => {
 86→                    tracing::warn!(
 87→                        id = %agent.moltis_id,
 88→                        error = %e,
 89→                        "openclaw import: failed to create agent persona"
 90→                    );
 91→                },
 92→            }
 93→        }
 94→        Ok(())
 95→    }
 96→
 97→    #[cfg(feature = "openclaw-import")]
 98→    async fn sync_imported_sessions_to_sqlite(&self, data_dir: &Path) -> Result<(), String> {
 99→        let metadata_path = data_dir.join("sessions").join("metadata.json");
100→        if !metadata_path.is_file() {
101→            return Ok(());
102→        }
103→
104→        let legacy_metadata = moltis_sessions::metadata::SessionMetadata::load(metadata_path)
105→            .map_err(|e| format!("failed to load imported metadata.json: {e}"))?;
106→
107→        for entry in legacy_metadata.list() {
108→            self.session_metadata
109→                .upsert(&entry.key, entry.label.clone())
110→                .await
111→                .map_err(|e| format!("failed to upsert session '{}': {e}", entry.key))?;
112→
113→            self.session_metadata
114→                .set_model(&entry.key, entry.model.clone())
115→                .await;
116→            self.session_metadata
117→                .set_project_id(&entry.key, entry.project_id.clone())
118→                .await;
119→            self.session_metadata
120→                .set_sandbox_enabled(&entry.key, entry.sandbox_enabled)
121→                .await;
122→            self.session_metadata
123→                .set_sandbox_image(&entry.key, entry.sandbox_image.clone())
124→                .await;
125→            self.session_metadata
126→                .set_worktree_branch(&entry.key, entry.worktree_branch.clone())
127→                .await;
128→            self.session_metadata
129→                .set_channel_binding(&entry.key, entry.channel_binding.clone())
130→                .await;
131→            self.session_metadata
132→                .set_parent(
133→                    &entry.key,
134→                    entry.parent_session_key.clone(),
135→                    entry.fork_point,
136→                )
137→                .await;
138→            self.session_metadata
139→                .set_mcp_disabled(&entry.key, entry.mcp_disabled)
140→                .await;
141→            if let Err(e) = self
142→                .session_metadata
143→                .set_agent_id(&entry.key, entry.agent_id.as_deref())
144→                .await
145→            {
146→                tracing::warn!(
147→                    key = %entry.key,
148→                    error = %e,
149→                    "openclaw import: failed to set agent_id on session"
150→                );
151→            }
152→            self.session_metadata
153→                .set_preview(&entry.key, entry.preview.as_deref())
154→                .await;
155→            self.session_metadata
156→                .set_timestamps_and_counts(
157→                    &entry.key,
158→                    entry.created_at,
159→                    entry.updated_at,
160→                    entry.message_count,
161→                    entry.last_seen_message_count,
162→                )
163→                .await;
164→        }
165→
166→        Ok(())
167→    }
168→}
