 1→//! Filesystem watcher for skill directories.
 2→//!
 3→//! Watches skill search paths for SKILL.md create/modify/delete events and sends
 4→//! notifications through a channel so the gateway can broadcast `skills.changed`.
 5→
 6→use std::path::PathBuf;
 7→
 8→use {
 9→    anyhow::Result,
10→    notify_debouncer_full::{
11→        DebounceEventResult, Debouncer, RecommendedCache, new_debouncer, notify::RecursiveMode,
12→    },
13→    tokio::sync::mpsc,
14→    tracing::{debug, info, warn},
15→};
16→
17→/// Events emitted by the skill watcher.
18→#[derive(Debug, Clone)]
19→pub enum SkillWatchEvent {
20→    /// A skill was created, modified, or deleted.
21→    Changed,
22→}
23→
24→/// Watches skill directories for SKILL.md changes with debouncing.
25→pub struct SkillWatcher {
26→    _debouncer: Debouncer<notify_debouncer_full::notify::RecommendedWatcher, RecommendedCache>,
27→}
28→
29→impl SkillWatcher {
30→    /// Start watching the given directories. Returns the watcher and a receiver for events.
31→    ///
32→    /// The watcher must be kept alive (not dropped) for events to continue.
33→    pub fn start(dirs: Vec<PathBuf>) -> Result<(Self, mpsc::UnboundedReceiver<SkillWatchEvent>)> {
34→        let (tx, rx) = mpsc::unbounded_channel();
35→
36→        let debouncer = new_debouncer(
37→            std::time::Duration::from_millis(500),
38→            None,
39→            move |result: DebounceEventResult| match result {
40→                Ok(events) => {
41→                    let mut changed = false;
42→                    for event in events {
43→                        for path in &event.paths {
44→                            let filename = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
45→                            if filename != "SKILL.md" {
46→                                continue;
47→                            }
48→
49→                            use notify_debouncer_full::notify::EventKind;
50→                            match event.kind {
51→                                EventKind::Create(_)
52→                                | EventKind::Modify(_)
53→                                | EventKind::Remove(_) => {
54→                                    debug!(path = %path.display(), "skill watcher event");
55→                                    changed = true;
56→                                },
57→                                _ => {},
58→                            }
59→                        }
60→                    }
61→                    if changed {
62→                        let _ = tx.send(SkillWatchEvent::Changed);
63→                    }
64→                },
65→                Err(errors) => {
66→                    for e in errors {
67→                        warn!(error = %e, "skill watcher error");
68→                    }
69→                },
70→            },
71→        )?;
72→
73→        let mut watcher = Self {
74→            _debouncer: debouncer,
75→        };
76→
77→        for dir in &dirs {
78→            if dir.exists() {
79→                watcher._debouncer.watch(dir, RecursiveMode::Recursive)?;
80→                info!(dir = %dir.display(), "skill watcher: watching directory");
81→            }
82→        }
83→
84→        Ok((watcher, rx))
85→    }
86→}
