 88→// ── Location requester ───────────────────────────────────────────────────────
 89→
 90→/// Gateway implementation of [`moltis_tools::location::LocationRequester`].
 91→///
 92→/// Uses the `PendingInvoke` + oneshot pattern to request the user's browser
 93→/// geolocation and waits for `location.result` RPC to resolve it.
 94→struct GatewayLocationRequester {
 95→    state: Arc<GatewayState>,
 96→}
 97→
 98→#[async_trait::async_trait]
 99→impl moltis_tools::location::LocationRequester for GatewayLocationRequester {
100→    async fn request_location(
101→        &self,
102→        conn_id: &str,
103→        precision: moltis_tools::location::LocationPrecision,
104→    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
105→        use moltis_tools::location::{LocationError, LocationResult};
106→
107→        let request_id = uuid::Uuid::new_v4().to_string();
108→
109→        // Send a location.request event to the browser client, including
110→        // the requested precision so JS can adjust geolocation options.
111→        let event = moltis_protocol::EventFrame::new(
112→            "location.request",
113→            serde_json::json!({ "requestId": request_id, "precision": precision }),
114→            self.state.next_seq(),
115→        );
116→        let event_json = serde_json::to_string(&event)?;
117→
118→        {
119→            let inner = self.state.inner.read().await;
120→            let clients = &inner.clients;
121→            let client = clients.get(conn_id).ok_or_else(|| {
122→                moltis_tools::Error::message(format!("no client connection for conn_id {conn_id}"))
123→            })?;
124→            if !client.send(&event_json) {
125→                return Err(moltis_tools::Error::message(format!(
126→                    "failed to send location request to client {conn_id}"
127→                )));
128→            }
129→        }
130→
131→        // Set up a oneshot for the result with timeout.
132→        let (tx, rx) = tokio::sync::oneshot::channel();
133→        {
134→            let mut inner_w = self.state.inner.write().await;
135→            let invokes = &mut inner_w.pending_invokes;
136→            invokes.insert(request_id.clone(), crate::state::PendingInvoke {
137→                request_id: request_id.clone(),
138→                sender: tx,
139→                created_at: std::time::Instant::now(),
140→            });
141→        }
142→
143→        // Wait up to 30 seconds for the user to grant/deny permission.
144→        let result = match tokio::time::timeout(std::time::Duration::from_secs(30), rx).await {
145→            Ok(Ok(value)) => value,
146→            Ok(Err(_)) => {
147→                // Sender dropped — clean up.
148→                self.state
149→                    .inner
150→                    .write()
151→                    .await
152→                    .pending_invokes
153→                    .remove(&request_id);
154→                return Ok(LocationResult {
155→                    location: None,
156→                    error: Some(LocationError::Timeout),
157→                });
158→            },
159→            Err(_) => {
160→                // Timeout — clean up.
161→                self.state
162→                    .inner
163→                    .write()
164→                    .await
165→                    .pending_invokes
166→                    .remove(&request_id);
167→                return Ok(LocationResult {
168→                    location: None,
169→                    error: Some(LocationError::Timeout),
170→                });
171→            },
172→        };
173→
174→        // Parse the result from the browser.
175→        if let Some(loc) = result.get("location") {
176→            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
177→            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
178→            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
179→            Ok(LocationResult {
180→                location: Some(moltis_tools::location::BrowserLocation {
181→                    latitude: lat,
182→                    longitude: lon,
183→                    accuracy,
184→                }),
185→                error: None,
186→            })
187→        } else if let Some(err) = result.get("error") {
188→            let code = err.get("code").and_then(|v| v.as_u64()).unwrap_or(0);
189→            let error = match code {
190→                1 => LocationError::PermissionDenied,
191→                2 => LocationError::PositionUnavailable,
192→                3 => LocationError::Timeout,
193→                _ => LocationError::NotSupported,
194→            };
195→            Ok(LocationResult {
196→                location: None,
197→                error: Some(error),
198→            })
199→        } else {
200→            Ok(LocationResult {
201→                location: None,
202→                error: Some(LocationError::PositionUnavailable),
203→            })
204→        }
205→    }
206→
207→    fn cached_location(&self) -> Option<moltis_config::GeoLocation> {
208→        self.state.inner.try_read().ok()?.cached_location.clone()
209→    }
210→
211→    async fn request_channel_location(
212→        &self,
213→        session_key: &str,
214→    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
215→        use moltis_tools::location::{LocationError, LocationResult};
216→
217→        // Look up channel binding from session metadata.
218→        let session_meta = self
219→            .state
220→            .services
221→            .session_metadata
222→            .as_ref()
223→            .ok_or_else(|| moltis_tools::Error::message("session metadata not available"))?;
224→        let entry = session_meta.get(session_key).await.ok_or_else(|| {
225→            moltis_tools::Error::message(format!("no session metadata for key {session_key}"))
226→        })?;
227→        let binding_json = entry.channel_binding.ok_or_else(|| {
228→            moltis_tools::Error::message(format!("no channel binding for session {session_key}"))
229→        })?;
230→        let reply_target: moltis_channels::ChannelReplyTarget =
231→            serde_json::from_str(&binding_json)?;
232→
233→        // Send a message asking the user to share their location.
234→        let outbound = self
235→            .state
236→            .services
237→            .channel_outbound_arc()
238→            .ok_or_else(|| moltis_tools::Error::message("no channel outbound available"))?;
239→        outbound
240→            .send_text(
241→                &reply_target.account_id,
242→                &reply_target.chat_id,
243→                "Please share your location in this chat.",
244→                None,
245→            )
246→            .await
247→            .map_err(|e| moltis_tools::Error::external("send location request", e))?;
248→
249→        // Create a pending invoke keyed by session.
250→        let pending_key = format!("channel_location:{session_key}");
251→        let (tx, rx) = tokio::sync::oneshot::channel();
252→        {
253→            let mut inner = self.state.inner.write().await;
254→            inner
255→                .pending_invokes
256→                .insert(pending_key.clone(), crate::state::PendingInvoke {
257→                    request_id: pending_key.clone(),
258→                    sender: tx,
259→                    created_at: std::time::Instant::now(),
260→                });
261→        }
262→
263→        // Wait up to 60 seconds — user needs to navigate Telegram's UI.
264→        let result = match tokio::time::timeout(std::time::Duration::from_secs(60), rx).await {
265→            Ok(Ok(value)) => value,
266→            Ok(Err(_)) => {
267→                self.state
268→                    .inner
269→                    .write()
270→                    .await
271→                    .pending_invokes
272→                    .remove(&pending_key);
273→                return Ok(LocationResult {
274→                    location: None,
275→                    error: Some(LocationError::Timeout),
276→                });
277→            },
278→            Err(_) => {
279→                self.state
280→                    .inner
281→                    .write()
282→                    .await
283→                    .pending_invokes
284→                    .remove(&pending_key);
285→                return Ok(LocationResult {
286→                    location: None,
287→                    error: Some(LocationError::Timeout),
288→                });
289→            },
290→        };
291→
292→        // Parse the result (same format as update_location sends).
293→        if let Some(loc) = result.get("location") {
294→            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
295→            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
296→            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
297→            Ok(LocationResult {
298→                location: Some(moltis_tools::location::BrowserLocation {
299→                    latitude: lat,
300→                    longitude: lon,
301→                    accuracy,
302→                }),
303→                error: None,
304→            })
305→        } else {
306→            Ok(LocationResult {
307→                location: None,
308→                error: Some(LocationError::PositionUnavailable),
309→            })
310→        }
311→    }
312→}
