321→fn instance_slug(config: &moltis_config::MoltisConfig) -> String {
322→    let mut raw_name = config.identity.name.clone();
323→    if let Some(file_identity) = moltis_config::load_identity_for_agent("main")
324→        && file_identity.name.is_some()
325→    {
326→        raw_name = file_identity.name;
327→    }
328→
329→    let base = raw_name
330→        .unwrap_or_else(|| "moltis".to_string())
331→        .to_lowercase();
332→    let mut out = String::new();
333→    let mut last_dash = false;
334→    for ch in base.chars() {
335→        let mapped = if ch.is_ascii_alphanumeric() {
336→            ch
337→        } else {
338→            '-'
339→        };
340→        if mapped == '-' {
341→            if !last_dash {
342→                out.push(mapped);
343→            }
344→            last_dash = true;
345→        } else {
346→            out.push(mapped);
347→            last_dash = false;
348→        }
349→    }
350→    let out = out.trim_matches('-').to_string();
351→    if out.is_empty() {
352→        "moltis".to_string()
353→    } else {
354→        out
355→    }
356→}
