366→fn env_value_with_overrides(env_overrides: &HashMap<String, String>, key: &str) -> Option<String> {
367→    std::env::var(key)
368→        .ok()
369→        .filter(|value| !value.trim().is_empty())
370→        .or_else(|| {
371→            env_overrides
372→                .get(key)
373→                .cloned()
374→                .filter(|value| !value.trim().is_empty())
375→        })
376→}
377→
378→fn merge_env_overrides(
379→    base_overrides: &HashMap<String, String>,
380→    additional: Vec<(String, String)>,
381→) -> HashMap<String, String> {
382→    let mut merged = base_overrides.clone();
383→    for (key, value) in additional {
384→        if key.trim().is_empty() || value.trim().is_empty() {
385→            continue;
386→        }
387→        merged.entry(key).or_insert(value);
388→    }
389→    merged
390→}
