  1→use std::path::{Path, PathBuf};
  2→
  3→use crate::types::SkillsManifest;
  4→
  5→/// Persistent manifest storage with atomic writes.
  6→pub struct ManifestStore {
  7→    path: PathBuf,
  8→}
  9→
 10→impl ManifestStore {
 11→    pub fn new(path: PathBuf) -> Self {
 12→        Self { path }
 13→    }
 14→
 15→    /// Default manifest path: `~/.moltis/skills-manifest.json`.
 16→    pub fn default_path() -> anyhow::Result<PathBuf> {
 17→        Ok(moltis_config::data_dir().join("skills-manifest.json"))
 18→    }
 19→
 20→    /// Load manifest from disk, returning a default if missing.
 21→    pub fn load(&self) -> anyhow::Result<SkillsManifest> {
 22→        if !self.path.exists() {
 23→            return Ok(SkillsManifest::default());
 24→        }
 25→        let data = std::fs::read_to_string(&self.path)?;
 26→        let manifest: SkillsManifest = serde_json::from_str(&data)?;
 27→        Ok(manifest)
 28→    }
 29→
 30→    /// Save manifest atomically via temp file + rename.
 31→    pub fn save(&self, manifest: &SkillsManifest) -> anyhow::Result<()> {
 32→        if let Some(parent) = self.path.parent() {
 33→            std::fs::create_dir_all(parent)?;
 34→        }
 35→        let tmp = self.path.with_extension("json.tmp");
 36→        let data = serde_json::to_string_pretty(manifest)?;
 37→        std::fs::write(&tmp, data)?;
 38→        std::fs::rename(&tmp, &self.path)?;
 39→        Ok(())
 40→    }
 41→
 42→    pub fn path(&self) -> &Path {
 43→        &self.path
 44→    }
 45→}
