112→
113→    let is_local = is_local_connection(&headers, addr, state.gateway_state.behind_proxy);
114→    let auth_result = check_auth(&state.credential_store, &headers, is_local).await;
115→    let authenticated = matches!(auth_result, AuthResult::Allowed(_));
116→    let setup_required = matches!(auth_result, AuthResult::SetupRequired);
117→
118→    let setup_code_required = state.gateway_state.inner.read().await.setup_code.is_some();
119→
120→    let webauthn_available = state.webauthn_registry.is_some();
121→
122→    let passkey_origins: Vec<String> = if let Some(registry) = state.webauthn_registry.as_ref() {
123→        registry.read().await.get_all_origins()
124→    } else {
125→        Vec::new()
126→    };
127→
128→    if !has_passkeys {
129→        state
