132→            .await;
133→    }
134→    let passkey_host_update_hosts = if has_passkeys {
135→        state.gateway_state.passkey_host_update_pending().await
136→    } else {
137→        Vec::new()
138→    };
139→    let passkey_host_update_required = !passkey_host_update_hosts.is_empty();
140→
141→    let setup_complete = state.credential_store.is_setup_complete();
142→
143→    Json(serde_json::json!({
144→        "setup_required": setup_required,
