146→        "has_passkeys": has_passkeys,
147→        "authenticated": authenticated,
148→        "auth_disabled": auth_disabled,
149→        "setup_code_required": setup_code_required,
150→        "has_password": has_password,
151→        "localhost_only": localhost_only,
152→        "webauthn_available": webauthn_available,
153→        "passkey_origins": passkey_origins,
154→        "passkey_host_update_required": passkey_host_update_required,
155→        "passkey_host_update_hosts": passkey_host_update_hosts,
156→    }))
