152→/// Discover registry skills using the manifest for enabled filtering.
153→///
154→/// Handles both formats:
155→/// - `PluginFormat::Skill` → parse `SKILL.md` from disk for full metadata
156→/// - Other formats → create stub metadata with `SkillSource::Plugin` (prompt_gen
157→///   uses the path as-is instead of appending `/SKILL.md`)
158→fn discover_registry(install_dir: &Path, skills: &mut Vec<SkillMetadata>) {
159→    let manifest_path = match ManifestStore::default_path() {
160→        Ok(p) => p,
161→        Err(_) => return,
162→    };
163→    let store = ManifestStore::new(manifest_path);
164→    let manifest = match store.load() {
165→        Ok(m) => m,
166→        Err(e) => {
167→            tracing::warn!(%e, "failed to load skills manifest");
168→            return;
169→        },
170→    };
171→
172→    for repo in &manifest.repos {
173→        for skill_state in &repo.skills {
174→            if !skill_state.enabled || !skill_state.trusted {
175→                continue;
176→            }
177→            let skill_dir = install_dir.join(&skill_state.relative_path);
178→
179→            match repo.format {
180→                PluginFormat::Skill => {
181→                    let skill_md = skill_dir.join("SKILL.md");
182→                    if !skill_md.is_file() {
183→                        tracing::warn!(?skill_md, "manifest references missing SKILL.md");
184→                        continue;
185→                    }
186→                    let content = match std::fs::read_to_string(&skill_md) {
187→                        Ok(c) => c,
188→                        Err(e) => {
189→                            tracing::warn!(?skill_md, %e, "failed to read SKILL.md");
190→                            continue;
191→                        },
192→                    };
193→                    match parse::parse_metadata(&content, &skill_dir) {
194→                        Ok(mut meta) => {
195→                            meta.source = Some(SkillSource::Registry);
196→                            tracing::info!(
197→                                path = %skill_md.display(),
198→                                source = "registry",
199→                                name = %meta.name,
200→                                "loaded SKILL.md"
201→                            );
202→                            skills.push(meta);
203→                        },
204→                        Err(e) => {
205→                            tracing::debug!(?skill_dir, %e, "skipping non-conforming SKILL.md");
206→                        },
207→                    }
208→                },
209→                _ => {
210→                    // Non-SKILL.md formats: stub metadata with Plugin source
211→                    // so prompt_gen uses the path directly (no /SKILL.md append).
212→                    skills.push(SkillMetadata {
213→                        name: skill_state.name.clone(),
214→                        description: String::new(),
215→                        homepage: None,
216→                        license: None,
217→                        compatibility: None,
218→                        allowed_tools: Vec::new(),
219→                        requires: Default::default(),
220→                        path: skill_dir,
221→                        source: Some(SkillSource::Plugin),
222→                        dockerfile: None,
223→                    });
224→                },
225→            }
226→        }
227→    }
228→}
