Sort the preferred model list alphabetically in the model dropdown.

In file `/Users/penso/.superset/worktrees/moltis/installation-feedback/crates/chat/src/lib.rs`, the `prioritize_models` function (lines 1567-1581) currently sorts by `(priority_rank, subscription_provider_rank, original_index)`. 

Current code:
```rust
    fn prioritize_models<'a>(
        order: &HashMap<String, usize>,
        models: impl Iterator<Item = &'a moltis_providers::ModelInfo>,
    ) -> Vec<&'a moltis_providers::ModelInfo> {
        let mut ordered: Vec<(usize, &'a moltis_providers::ModelInfo)> =
            models.enumerate().collect();
        ordered.sort_by_key(|(idx, model)| {
            (
                Self::priority_rank(order, model),
                subscription_provider_rank(&model.provider),
                *idx,
            )
        });
        ordered.into_iter().map(|(_, model)| model).collect()
    }
```

Change the sort to group preferred models (rank != usize::MAX) first, then sort alphabetically by display_name within each group. We need to use `sort_by` instead of `sort_by_key` since we need to compare strings. The new logic should be:

```rust
    fn prioritize_models<'a>(
        order: &HashMap<String, usize>,
        models: impl Iterator<Item = &'a moltis_providers::ModelInfo>,
    ) -> Vec<&'a moltis_providers::ModelInfo> {
        let mut ordered: Vec<(usize, &'a moltis_providers::ModelInfo)> =
            models.enumerate().collect();
        ordered.sort_by(|(idx_a, a), (idx_b, b)| {
            let rank_a = Self::priority_rank(order, a);
            let rank_b = Self::priority_rank(order, b);
            // Preferred (rank != MAX) first, then non-preferred
            let bucket_a = if rank_a == usize::MAX { 1u8 } else { 0 };
            let bucket_b = if rank_b == usize::MAX { 1u8 } else { 0 };
            bucket_a
                .cmp(&bucket_b)
                .then_with(|| a.display_name.to_lowercase().cmp(&b.display_name.to_lowercase()))
                .then_with(|| subscription_provider_rank(&a.provider).cmp(&subscription_provider_rank(&b.provider)))
                .then_with(|| idx_a.cmp(idx_b))
        });
        ordered.into_iter().map(|(_, model)| model).collect()
    }
```

