    }

    fn models_enabled(&self) -> bool {
        self.include_models.unwrap_or(true)
    }

    fn projects_enabled(&self) -> bool {
        self.include_projects.unwrap_or(true)
    }

    fn counts_enabled(&self) -> bool {
